	(1, '미지정디자인', '미지정디자인', 1, 3, 1, '', '2', NULL, '', '', 'Y', '2026-04-18 20:24:11', '2026-04-23 21:09:59', 'cstmsg', 'cstmsg', '이동기', '이동기'),
	(2, '루다법무사2', '루다법무사2', 1, 3, 1, '<!DOCTYPE html>\r\n<html lang="ko">\r\n<head>\r\n    <meta charset="UTF-8">\r\n	<meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">\r\n    <title>루다법무사 - 개인회생 상담</title>\r\n    <link rel="preconnect" href="https://fonts.googleapis.com">\r\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\r\n    <link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@400;500;700;900&family=Black+Han+Sans&display=swap" rel="stylesheet">\r\n    <style>\r\n        * {\r\n            margin: 0;\r\n            padding: 0;\r\n            box-sizing: border-box;\r\n        }\r\n\r\n        body {\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            background: #f5f5f5;\r\n            margin: 0;\r\n            padding: 0;\r\n            overflow-x: hidden;\r\n        }\r\n\r\n        .container {\r\n            max-width: 800px;\r\n            margin: 0 auto;\r\n            background: white;\r\n            width: 100%;\r\n        }\r\n\r\n        /* 섹션 컨테이너 */\r\n        .section-container {\r\n            position: relative;\r\n            width: 100%;\r\n            overflow: hidden;\r\n        }\r\n\r\n        /* 이미지 슬라이드 */\r\n        .image-slide {\r\n            width: 100%;\r\n            display: none;\r\n        }\r\n\r\n        .image-slide.active {\r\n            display: block;\r\n        }\r\n\r\n        .image-slide img {\r\n            width: 100%;\r\n            height: auto;\r\n            display: block;\r\n            max-width: 100%;\r\n            object-fit: cover;\r\n        }\r\n\r\n        /* 폼 헤더 스타일 - 네이비 블루 */\r\n        .form-header {\r\n            background: linear-gradient(180deg, #042b76 0%, #042b76 100%);\r\n            padding: 40px 20px;\r\n            text-align: center;\r\n            color: white;\r\n            display: none;\r\n        }\r\n\r\n        .form-header.active {\r\n            display: block;\r\n        }\r\n\r\n        .form-header h1 {\r\n            font-size: 32px;\r\n            font-weight: 900;\r\n            margin-bottom: 10px;\r\n            line-height: 1.3;\r\n        }\r\n\r\n        .form-header h2 {\r\n            font-size: 28px;\r\n            font-weight: 700;\r\n            color: #fbbf24;\r\n            margin: 0;\r\n        }\r\n\r\n        /* 폼 섹션 - 밝은 회색 배경 */\r\n        .form-section {\r\n            background: #e5e7eb;\r\n            padding: 50px 30px;\r\n            display: none;\r\n        }\r\n\r\n        .form-section.active {\r\n            display: block;\r\n        }\r\n\r\n        .form-group {\r\n            margin-bottom: 20px;\r\n        }\r\n\r\n        .form-label {\r\n            display: flex;\r\n            align-items: center;\r\n            font-size: 22px;\r\n            font-weight: 700;\r\n            color: #1f2937;\r\n            margin-bottom: 20px;\r\n        }\r\n\r\n        .form-label::before {\r\n            content: \'◆\';\r\n            margin-right: 10px;\r\n            color: #1f2937;\r\n            font-size: 18px;\r\n        }\r\n\r\n        /* 라디오 버튼 스타일 */\r\n        .radio-group {\r\n            display: flex;\r\n            flex-direction: column;\r\n            gap: 15px;\r\n        }\r\n\r\n        .radio-option {\r\n            display: flex;\r\n            align-items: center;\r\n        }\r\n\r\n        .radio-option input[type="radio"] {\r\n            width: 24px;\r\n            height: 24px;\r\n            margin-right: 12px;\r\n            cursor: pointer;\r\n            accent-color: #1e3a8a;\r\n        }\r\n\r\n        .radio-label {\r\n            font-size: 20px;\r\n            font-weight: 500;\r\n            color: #374151;\r\n            cursor: pointer;\r\n        }\r\n\r\n        /* 작은 빨간 텍스트 */\r\n        .info-text {\r\n            color: #dc2626;\r\n            font-size: 16px;\r\n            margin-top: 15px;\r\n            line-height: 1.6;\r\n        }\r\n\r\n        /* 입력 필드 */\r\n        .input-field {\r\n            width: 100%;\r\n            padding: 15px;\r\n            border: 2px solid #d1d5db;\r\n            border-radius: 4px;\r\n            font-size: 18px;\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            background: white;\r\n        }\r\n\r\n        .input-field:focus {\r\n            outline: none;\r\n            border-color: #1e3a8a;\r\n        }\r\n\r\n        .tel-group {\r\n            display: grid;\r\n            grid-template-columns: 100px 1fr 1fr;\r\n            gap: 10px;\r\n        }\r\n\r\n        .tel-fixed {\r\n            background: #f3f4f6;\r\n            color: #6b7280;\r\n            cursor: not-allowed;\r\n        }\r\n\r\n        select.input-field {\r\n            cursor: pointer;\r\n        }\r\n\r\n        textarea.input-field {\r\n            min-height: 120px;\r\n            resize: vertical;\r\n        }\r\n\r\n        .submit-btn {\r\n            width: 100%;\r\n            padding: 20px;\r\n            background: #1e3a8a;\r\n            color: white;\r\n            border: none;\r\n            border-radius: 4px;\r\n            font-size: 20px;\r\n            font-weight: 700;\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            cursor: pointer;\r\n            margin-top: 30px;\r\n        }\r\n\r\n        .submit-btn:hover {\r\n            background: #1e40af;\r\n        }\r\n\r\n        .submit-btn:active {\r\n            background: #1e3a8a;\r\n        }\r\n\r\n        /* 네비게이션 버튼 */\r\n        .navigation-buttons {\r\n            display: flex;\r\n            justify-content: space-between;\r\n            padding: 30px 20px;\r\n            background: #f5f5f5;\r\n        }\r\n\r\n        .nav-btn {\r\n            padding: 15px 40px;\r\n            min-width: 200px;\r\n            background: #1e3a8a;\r\n            color: white;\r\n            border: none;\r\n            border-radius: 4px;\r\n            font-size: 18px;\r\n            font-weight: 700;\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            cursor: pointer;\r\n            transition: background 0.3s;\r\n        }\r\n\r\n        .nav-btn:hover:not(:disabled) {\r\n            background: #1e40af;\r\n        }\r\n\r\n        .nav-btn:disabled {\r\n            background: #d1d5db;\r\n            color: #9ca3af;\r\n            cursor: not-allowed;\r\n        }\r\n\r\n        /* 반응형 */\r\n        @media (max-width: 768px) {\r\n            .form-header h1 {\r\n                font-size: 24px;\r\n            }\r\n\r\n            .form-header h2 {\r\n                font-size: 20px;\r\n            }\r\n\r\n            .form-section {\r\n                padding: 30px 20px;\r\n            }\r\n\r\n            .form-label {\r\n                font-size: 18px;\r\n            }\r\n\r\n            .radio-label {\r\n                font-size: 16px;\r\n            }\r\n\r\n            .tel-group {\r\n                grid-template-columns: 80px 1fr 1fr;\r\n            }\r\n\r\n            .input-field {\r\n                font-size: 16px;\r\n                padding: 12px;\r\n            }\r\n\r\n            .submit-btn {\r\n                font-size: 18px;\r\n                padding: 18px;\r\n            }\r\n\r\n            .info-text {\r\n                font-size: 14px;\r\n            }\r\n\r\n            .nav-btn {\r\n                padding: 12px 30px;\r\n                font-size: 16px;\r\n            }\r\n\r\n            .navigation-buttons {\r\n                padding: 20px 15px;\r\n            }\r\n        }\r\n\r\n        @media (max-width: 480px) {\r\n            .form-header {\r\n                padding: 30px 15px;\r\n            }\r\n\r\n            .form-header h1 {\r\n                font-size: 20px;\r\n            }\r\n\r\n            .form-header h2 {\r\n                font-size: 18px;\r\n            }\r\n\r\n            .form-section {\r\n                padding: 20px 15px;\r\n            }\r\n\r\n            .form-label {\r\n                font-size: 16px;\r\n            }\r\n\r\n            .radio-label {\r\n                font-size: 15px;\r\n            }\r\n\r\n            .tel-group {\r\n                grid-template-columns: 70px 1fr 1fr;\r\n                gap: 8px;\r\n            }\r\n\r\n            .nav-btn {\r\n                padding: 10px 25px;\r\n                font-size: 15px;\r\n            }\r\n\r\n            .navigation-buttons {\r\n                gap: 15px;\r\n            }\r\n        }\r\n		\r\n        /* footer */\r\n        .site-footer {\r\n            background: #111827;\r\n            color: #e5e7eb;\r\n            padding: 32px 24px 40px;\r\n            border-top: 4px solid #1e3a8a;\r\n        }\r\n\r\n        .footer-inner {\r\n            max-width: 800px;\r\n            margin: 0 auto;\r\n        }\r\n\r\n        .footer-title {\r\n            font-size: 22px;\r\n            font-weight: 800;\r\n            color: #ffffff;\r\n            margin-bottom: 18px;\r\n            letter-spacing: -0.3px;\r\n        }\r\n\r\n        .footer-info {\r\n            display: flex;\r\n            flex-direction: column;\r\n            gap: 10px;\r\n        }\r\n\r\n        .footer-row {\r\n            display: flex;\r\n            flex-wrap: wrap;\r\n            gap: 8px;\r\n            font-size: 10px;\r\n            line-height: 1.7;\r\n            color: #d1d5db;\r\n        }\r\n\r\n        .footer-label {\r\n            font-weight: 700;\r\n            color: #9ca3af;\r\n            min-width: 110px;\r\n        }\r\n\r\n        .footer-value {\r\n            flex: 1;\r\n            min-width: 0;\r\n            color: #f3f4f6;\r\n            word-break: keep-all;\r\n        }\r\n\r\n        .footer-copy {\r\n            margin-top: 22px;\r\n            padding-top: 18px;\r\n            border-top: 1px solid rgba(255, 255, 255, 0.12);\r\n            font-size: 13px;\r\n            color: #9ca3af;\r\n            line-height: 1.6;\r\n        }\r\n\r\n        @media (max-width: 768px) {\r\n            .site-footer {\r\n                padding: 26px 18px 32px;\r\n            }\r\n\r\n            .footer-title {\r\n                font-size: 18px;\r\n                margin-bottom: 14px;\r\n            }\r\n\r\n            .footer-row {\r\n                flex-direction: column;\r\n                gap: 2px;\r\n                font-size: 10px;\r\n            }\r\n\r\n            .footer-label {\r\n                min-width: auto;\r\n            }\r\n\r\n            .footer-copy {\r\n                font-size: 12px;\r\n            }\r\n        }\r\n		\r\n		/* 중앙 화살표 버튼 */\r\n        .center-arrows {\r\n            position: fixed;\r\n            top: 50vh;\r\n            left: 50%;\r\n            transform: translate(-50%, -50%);\r\n            width: 100%;\r\n            max-width: 800px;\r\n            display: flex;\r\n            justify-content: space-between;\r\n            padding: 0 20px;\r\n            pointer-events: none;\r\n            z-index: 100;\r\n        }\r\n\r\n        .arrow-btn {\r\n            width: 50px;\r\n            height: 50px;\r\n            background: rgba(0, 0, 0, 0.5);\r\n            color: white;\r\n            border: none;\r\n            border-radius: 50%;\r\n            font-size: 24px;\r\n            cursor: pointer;\r\n            pointer-events: auto;\r\n            transition: background 0.3s;\r\n            display: flex;\r\n            flex-direction: column;\r\n            align-items: center;\r\n            justify-content: center;\r\n            line-height: 1;\r\n        }\r\n\r\n        .arrow-label {\r\n            font-size: 10px;\r\n            opacity: 0.7;\r\n            margin-top: 2px;\r\n        }\r\n\r\n        .arrow-btn:hover:not(:disabled) {\r\n            background: rgba(0, 0, 0, 0.7);\r\n        }\r\n\r\n        .arrow-btn:disabled {\r\n            background: rgba(200, 200, 200, 0.3);\r\n            color: rgba(255, 255, 255, 0.5);\r\n            cursor: not-allowed;\r\n        }\r\n\r\n        @media (max-width: 768px) {\r\n            .arrow-btn {\r\n                width: 40px;\r\n                height: 40px;\r\n                font-size: 20px;\r\n            }\r\n\r\n            .arrow-label {\r\n                font-size: 9px;\r\n            }\r\n\r\n            .center-arrows {\r\n                padding: 0 10px;\r\n            }\r\n        }\r\n\r\n        @media (max-width: 480px) {\r\n            .arrow-btn {\r\n                width: 35px;\r\n                height: 35px;\r\n                font-size: 18px;\r\n            }\r\n\r\n            .arrow-label {\r\n                font-size: 8px;\r\n            }\r\n\r\n            .center-arrows {\r\n                padding: 0 5px;\r\n            }\r\n        }\r\n		\r\n    </style>\r\n</head>\r\n<body>\r\n    <div class="container">\r\n        <!-- [DIV1] 상단 섹션 -->\r\n        <div class="section-container" id="section1">\r\n		\r\n			<!-- 중앙 화살표 버튼 -->\r\n            <div class="center-arrows">\r\n                <button class="arrow-btn" id="centerPrev1" onclick="navigate1(-1)">\r\n                    ‹<span class="arrow-label">이전</span>\r\n                </button>\r\n                <button class="arrow-btn" id="centerNext1" onclick="navigate1(1)">\r\n                    ›<span class="arrow-label">다음</span>\r\n                </button>\r\n            </div>\r\n			\r\n            <!-- 이미지1 -->\r\n            <div class="image-slide active" id="image1-1">\r\n                <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page01/01_mz%20%ED%9A%8C%EC%83%9D.gif" alt="슬라이드 1">\r\n            </div>\r\n            \r\n            <!-- 이미지2 -->\r\n            <div class="image-slide" id="image1-2">\r\n                <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page01/02_mz%20%ED%9A%8C%EC%83%9D.jpg" alt="슬라이드 2">\r\n            </div>\r\n            \r\n            <!-- 입력폼1-1 헤더 -->\r\n            <div class="form-header" id="formHeader1-1">\r\n                <h1>상담 = 신청 아닙니다</h1>\r\n                <h2>먼저 탕감률을 확인해보세요</h2>\r\n            </div>\r\n\r\n            <!-- 입력폼1-1 (빚 정보) -->\r\n            <div class="form-section" id="formSection1-1">\r\n                <form id="consultForm1-1">\r\n                    <!-- 현재 탕감이 필요한 빚은 얼마인가요 -->\r\n                    <div class="form-group">\r\n                        <label class="form-label">현재 탕감이 필요한 빚은 얼마인가요?</label>\r\n                        <div class="radio-group">\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="debt1-1" name="inputted2" value="2천만 원 미만" required>\r\n                                <label for="debt1-1" class="radio-label">2천만 원 미만</label>\r\n                            </div>\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="debt2-1" name="inputted2" value="2천만 원 ~ 5천만 원">\r\n                                <label for="debt2-1" class="radio-label">2천만 원 ~ 5천만 원</label>\r\n                            </div>\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="debt3-1" name="inputted2" value="5천만 원 ~ 8천만 원">\r\n                                <label for="debt3-1" class="radio-label">5천만 원 ~ 8천만 원</label>\r\n                            </div>\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="debt4-1" name="inputted2" value="8천만 원 ~ 1억 원 미만">\r\n                                <label for="debt4-1" class="radio-label">8천만 원 ~ 1억 원 미만</label>\r\n                            </div>\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="debt5-1" name="inputted2" value="1억 원 이상">\r\n                                <label for="debt5-1" class="radio-label">1억 원 이상</label>\r\n                            </div>\r\n                        </div>\r\n                        <p class="info-text">(신용대출·카드빚·코인·주식 채무가 2천만 원 이상이면<br>개인회생이 가능한 경우가 대부분입니다)</p>\r\n                    </div>\r\n\r\n                    <!-- 현재 빚이 주로 어떤 종류인가요 -->\r\n                    <div class="form-group">\r\n                        <label class="form-label">현재 빚이 주로 어떤 종류인가요?</label>\r\n                        <div class="radio-group">\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="type1-1" name="inputted3" value="신용대출 / 카드빚" required>\r\n                                <label for="type1-1" class="radio-label">신용대출 / 카드빚</label>\r\n                            </div>\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="type2-1" name="inputted3" value="코인 · 주식 관련 대출">\r\n                                <label for="type2-1" class="radio-label">코인 · 주식 관련 대출</label>\r\n                            </div>\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="type3-1" name="inputted3" value="사업자 대출 (개인 명의)">\r\n                                <label for="type3-1" class="radio-label">사업자 대출 (개인 명의)</label>\r\n                            </div>\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="type4-1" name="inputted3" value="병원비 · 생활비 대출">\r\n                                <label for="type4-1" class="radio-label">병원비 · 생활비 대출</label>\r\n                            </div>\r\n                            <div class="radio-option">\r\n                                <input type="radio" id="type5-1" name="inputted3" value="담보대출 (주택 · 아파트)">\r\n                                <label for="type5-1" class="radio-label">담보대출 (주택 · 아파트)</label>\r\n                            </div>\r\n                        </div>\r\n                        <p class="info-text">(2024년 법원 통계 기준 실질 당감률 평균 70% 이상<br>사업자 채무는 최대 80%에 가까운 법원 사례)</p>\r\n                    </div>\r\n                </form>\r\n            </div>\r\n			\r\n			<!-- 이미지3 -->\r\n            <div class="image-slide" id="image1-3">\r\n                <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page02/03_mz%ED%9A%8C%EC%83%9D%20%EC%8A%AC%EB%9D%BC%EC%9D%B4%EB%93%9C%20%ED%8F%AC%ED%95%A8.gif" alt="슬라이드 3">\r\n            </div>\r\n            \r\n            <!-- 이미지4 -->\r\n            <div class="image-slide" id="image1-4">\r\n                <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page02/05_MZ%ED%9A%8C%EC%83%9D%20-%20%ED%83%95%EA%B0%90%EB%A5%A0.jpg" alt="슬라이드 4">\r\n            </div>\r\n			\r\n\r\n            <!-- 입력폼1-2 헤더 -->\r\n            <div class="form-header" id="formHeader1-2">\r\n                <h1>상담 = 신청 아닙니다</h1>\r\n                <h2>먼저 탕감률을 확인해보세요</h2>\r\n            </div>\r\n\r\n            <!-- 입력폼1-2 (개인정보 & 제출) -->\r\n            <div class="form-section" id="formSection1-2">\r\n                <form id="consultForm1-2" action="submit.html" method="POST">\r\n                    <!-- 이름 -->\r\n                    <div class="form-group">\r\n                        <label class="form-label">이름</label>\r\n                        <input type="text" name="name" class="input-field" placeholder="이름을 입력해주세요" required>\r\n                    </div>\r\n\r\n                    <!-- 연락처 -->\r\n                    <div class="form-group">\r\n                        <label class="form-label">연락처</label>\r\n                        <div class="tel-group">\r\n                            <input type="text" name="tel1" value="010" class="input-field tel-fixed" readonly>\r\n                            <input type="text" name="tel2" class="input-field tel2-1" placeholder="1234" maxlength="4" pattern="[0-9]{3,4}" required>\r\n                            <input type="text" name="tel3" class="input-field tel3-1" placeholder="5678" maxlength="4" pattern="[0-9]{4}" required>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <!-- 상담가능시간 -->\r\n                    <div class="form-group">\r\n                        <label class="form-label">상담 가능 시간</label>\r\n                        <select name="inputted1" class="input-field" required>\r\n                            <option value="">선택해주세요</option>\r\n                            <option value="오전">오전 (09:00 - 12:00)</option>\r\n                            <option value="점심">점심 (12:00 - 14:00)</option>\r\n                            <option value="오후">오후 (14:00 - 18:00)</option>\r\n                        </select>\r\n                    </div>\r\n\r\n                    <!-- 상담메모 -->\r\n                    <div class="form-group">\r\n                        <label class="form-label">상담 메모</label>\r\n                        <textarea name="inputted5" class="input-field" placeholder="상담받고 싶은 내용을 자유롭게 작성해주세요 (선택사항)"></textarea>\r\n                    </div>\r\n\r\n                    <!-- 개인정보 동의 -->\r\n                    <div class="form-group" style="display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 10px;">\r\n                        <label style="display: flex; align-items: center; cursor: pointer; flex: 1;">\r\n                            <input type="checkbox" required style="width: 20px; height: 20px; margin-right: 10px; cursor: pointer;">\r\n                            <span style="font-size: 16px; color: #333;">개인정보 수집 및 상담 연락에 동의합니다. (필수)</span>\r\n                        </label>\r\n                        <button type="button" onclick="openPrivacyModal()" style="padding: 8px 16px; background: #666; color: white; border: none; border-radius: 4px; font-size: 14px; cursor: pointer;">약관 보기</button>\r\n                    </div>\r\n\r\n                    <!-- 제출 버튼 -->\r\n                    <button type="submit" class="submit-btn">무료 상담 신청하기</button>\r\n                    \r\n                    <!-- 숨겨진 필드 (이전 폼 데이터 저장용) -->\r\n                    <input type="hidden" name="inputted2" id="hidden-debt-1">\r\n                    <input type="hidden" name="inputted3" id="hidden-type-1">\r\n                </form>\r\n            </div>\r\n\r\n            <!-- 네비게이션 버튼 -->\r\n            <div class="navigation-buttons">\r\n                <button class="nav-btn" id="prev1" onclick="navigate1(-1)">이전</button>\r\n                <button class="nav-btn" id="next1" onclick="navigate1(1)">다음</button>\r\n            </div>\r\n			\r\n        </div>\r\n\r\n        \r\n    </div>	\r\n    \r\n    <footer class="site-footer">\r\n        <div class="footer-inner">\r\n			<!--<div class="footer-title">루다 합동법무사사무소</div>-->\r\n            \r\n            <div class="footer-info">\r\n			\r\n				<div class="footer-row">\r\n                    <span class="footer-label">주소</span>\r\n                    <span class="footer-value">서울시 강남구 테헤란로21길 5, 10층(역삼동, 이너스타워)</span>\r\n                </div>\r\n				\r\n                <div class="footer-row">\r\n                    <span class="footer-label">사업자등록번호</span>\r\n                    <span class="footer-value">209-44-91325</span>\r\n                </div>\r\n\r\n                <div class="footer-row">\r\n                    <span class="footer-label">대표</span>\r\n                    <span class="footer-value">김현기</span>\r\n                </div>\r\n\r\n                \r\n            </div>\r\n\r\n            <!--<div class="footer-copy">-->\r\n            <!--    © 루다 합동법무사사무소. All rights reserved.-->\r\n            <!--</div>-->\r\n        </div>\r\n    </footer>\r\n\r\n    <!-- 개인정보 약관 모달 -->\r\n    <div id="privacyModal" style="display: none; position: fixed; z-index: 9999; left: 0; top: 0; width: 100%; height: 100%; background: rgba(0, 0, 0, 0.6); align-items: center; justify-content: center;">\r\n        <div style="background: white; padding: 30px; border-radius: 16px; max-width: 600px; width: 90%; max-height: 80vh; overflow-y: auto; box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);">\r\n            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; padding-bottom: 15px; border-bottom: 2px solid #eee;">\r\n                <h3 style="font-size: 22px; font-weight: 700; color: #333; margin: 0;">개인정보 취급방침</h3>\r\n                <button onclick="closePrivacyModal()" style="background: none; border: none; font-size: 28px; cursor: pointer; color: #999; width: 36px; height: 36px; display: flex; align-items: center; justify-content: center; border-radius: 50%;">&times;</button>\r\n            </div>\r\n            <div style="font-size: 14px; line-height: 1.8; color: #555;">\r\n                <h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 0; margin-bottom: 15px;">1. 개인정보의 수집 및 이용목적</h4>\r\n                <p style="margin-bottom: 20px;">성명, 연락처, 이메일, 상담연락종류, 상담희망시간, 상담 메모는 원활한 의사소통 경로의 확보, 이벤트성 정보 전달, 접속 빈도 파악 또는 회원의 서비스 이용에 대한 통계자료로 활용됩니다.</p>\r\n\r\n                <h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 15px;">2. 개인정보의 보유 및 이용기간</h4>\r\n                <p style="margin-bottom: 10px;">- 수집된 고객의 개인정보는 처리 목적 달성 등 그 개인정보가 불필요하게 되었을 때에는 DB에서 삭제하고 있습니다.</p>\r\n                <p style="margin-bottom: 10px;">- 정보제공자가 개인정보 삭제를 요청할 경우 즉시 삭제합니다. 단, 타법령의 규정에 의해 보유하도록 한 기간 동안은 보관할 수 있습니다.</p>\r\n                <p style="margin-bottom: 10px;">- 소비자의 불만 또는 분쟁처리에 관한 기록 : 3년<br>\r\n                (전자상거래 등에서의 소비자보호에 관한 법률)</p>\r\n                <p style="margin-bottom: 10px;">- 신용정보의 수집/처리 및 이용 등에 관한 기록 : 3년<br>\r\n                (신용정보의 이용 및 보호에 관한 법률)</p>\r\n                <p style="margin-bottom: 20px;">- 본인 확인에 관한 기록 : 6개월<br>\r\n                (정보통신망 이용촉진 및 정보보호 등에 관한 법률)</p>\r\n\r\n                <h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 15px;">3. 개인정보 제공 동의 거부 권리 및 동의 거부에 따른 불이익 내용 또는 제한사항</h4>\r\n                <p style="margin-bottom: 10px;">귀하는 개인정보 제공 동의를 거부할 권리가 있으며, 동의 거부에 따른 불이익은 없습니다.</p>\r\n                <p style="margin-bottom: 0; padding: 15px; background: #f9fafb; border-left: 3px solid #1e3a8a; border-radius: 4px; font-size: 13px; color: #666;">※ 개인정보 제공자가 동의한 내용 외의 다른 목적으로 활용하지 않으며, 제공된 개인정보의 이용을 거부하고자 할 때에는 개인정보 관리책임자를 통해 열람, 정정, 삭제를 요구할 수 있습니다.</p>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <script>\r\n        \r\n        // 현재 상태 (0: 이미지1, 1: 이미지2, 2: 입력폼1, 3: 이미지3, 4: 이미지4, 5: 입력폼2)\r\n        let currentState1 = 0;\r\n\r\n\r\n\r\n        // 섹션1 네비게이션\r\n        function navigate1(direction) {\r\n            // 다음 버튼 클릭 시 폼 검증\r\n            if (direction === 1 && currentState1 === 2) {\r\n                const form = document.getElementById(\'consultForm1-1\');\r\n                if (!form.checkValidity()) {\r\n                    form.reportValidity();\r\n                    return;\r\n                }\r\n                // 폼 데이터 저장\r\n                saveFormData1();\r\n            }\r\n            \r\n            currentState1 += direction;\r\n            \r\n            // 범위 제한\r\n            if (currentState1 < 0) currentState1 = 0;\r\n            if (currentState1 > 5) currentState1 = 5;\r\n\r\n\r\n            \r\n            updateSection1();\r\n        }\r\n\r\n        function saveFormData1() {\r\n            const debtValue = document.querySelector(\'input[name="inputted2"]:checked\')?.value;\r\n            const typeValue = document.querySelector(\'input[name="inputted3"]:checked\')?.value;\r\n            \r\n            document.getElementById(\'hidden-debt-1\').value = debtValue || \'\';\r\n            document.getElementById(\'hidden-type-1\').value = typeValue || \'\';\r\n        }\r\n\r\n        function updateSection1() {\r\n            const image1 = document.getElementById(\'image1-1\');\r\n            const image2 = document.getElementById(\'image1-2\');\r\n            const image3 = document.getElementById(\'image1-3\');\r\n            const image4 = document.getElementById(\'image1-4\');\r\n            const formHeader1 = document.getElementById(\'formHeader1-1\');\r\n            const formSection1 = document.getElementById(\'formSection1-1\');\r\n            const formHeader2 = document.getElementById(\'formHeader1-2\');\r\n            const formSection2 = document.getElementById(\'formSection1-2\');\r\n            const prevBtn = document.getElementById(\'prev1\');\r\n            const nextBtn = document.getElementById(\'next1\');\r\n            const centerPrevBtn = document.getElementById(\'centerPrev1\');\r\n            const centerNextBtn = document.getElementById(\'centerNext1\');\r\n            \r\n            // 모두 숨기기\r\n            image1.classList.remove(\'active\');\r\n            image2.classList.remove(\'active\');\r\n            image3.classList.remove(\'active\');\r\n            image4.classList.remove(\'active\');\r\n            formHeader1.classList.remove(\'active\');\r\n            formSection1.classList.remove(\'active\');\r\n            formHeader2.classList.remove(\'active\');\r\n            formSection2.classList.remove(\'active\');\r\n            \r\n            // 현재 상태에 따라 표시\r\n            if (currentState1 === 0) {\r\n                image1.classList.add(\'active\');\r\n                prevBtn.disabled = true;\r\n                nextBtn.disabled = false;\r\n                centerPrevBtn.disabled = true;\r\n                centerNextBtn.disabled = false;\r\n            } else if (currentState1 === 1) {\r\n                image2.classList.add(\'active\');\r\n                prevBtn.disabled = false;\r\n                nextBtn.disabled = false;\r\n                centerPrevBtn.disabled = false;\r\n                centerNextBtn.disabled = false;\r\n            } else if (currentState1 === 2) {\r\n                formHeader1.classList.add(\'active\');\r\n                formSection1.classList.add(\'active\');\r\n                prevBtn.disabled = false;\r\n                nextBtn.disabled = false;\r\n                centerPrevBtn.disabled = false;\r\n                centerNextBtn.disabled = false;\r\n            } else if (currentState1 === 3) {\r\n                image3.classList.add(\'active\');\r\n                prevBtn.disabled = false;\r\n                nextBtn.disabled = false;\r\n                centerPrevBtn.disabled = false;\r\n                centerNextBtn.disabled = false;\r\n            } else if (currentState1 === 4) {\r\n                image4.classList.add(\'active\');\r\n                prevBtn.disabled = false;\r\n                nextBtn.disabled = false;\r\n                centerPrevBtn.disabled = false;\r\n                centerNextBtn.disabled = false;\r\n            } else if (currentState1 === 5) {\r\n                formHeader2.classList.add(\'active\');\r\n                formSection2.classList.add(\'active\');\r\n                prevBtn.disabled = false;\r\n                nextBtn.disabled = true;\r\n                centerPrevBtn.disabled = false;\r\n                centerNextBtn.disabled = true;\r\n            }\r\n        }\r\n\r\n        \r\n        // 페이지 로드 시 초기 상태 설정\r\n        window.addEventListener(\'DOMContentLoaded\', function() {\r\n            updateSection1();\r\n            updateSection2();\r\n        });\r\n\r\n        // 개인정보 약관 모달\r\n        function openPrivacyModal() {\r\n            const modal = document.getElementById(\'privacyModal\');\r\n            modal.style.display = \'flex\';\r\n            document.body.style.overflow = \'hidden\';\r\n        }\r\n\r\n        function closePrivacyModal() {\r\n            const modal = document.getElementById(\'privacyModal\');\r\n            modal.style.display = \'none\';\r\n            document.body.style.overflow = \'auto\';\r\n        }\r\n\r\n        // 모달 배경 클릭 시 닫기\r\n        document.getElementById(\'privacyModal\').addEventListener(\'click\', function(e) {\r\n            if (e.target === this) {\r\n                closePrivacyModal();\r\n            }\r\n        });\r\n\r\n        // 전화번호 입력 시 자동 포커스 이동\r\n        document.querySelectorAll(\'.tel2-1, .tel2-2\').forEach(input => {\r\n            input.addEventListener(\'input\', function(e) {\r\n                if (this.value.length === 4) {\r\n                    const parent = this.closest(\'.tel-group\');\r\n                    const tel3 = parent.querySelector(\'.tel3-1, .tel3-2\');\r\n                    if (tel3) tel3.focus();\r\n                }\r\n            });\r\n        });\r\n\r\n        // 숫자만 입력 가능하도록\r\n        document.querySelectorAll(\'.tel2-1, .tel2-2, .tel3-1, .tel3-2\').forEach(input => {\r\n            input.addEventListener(\'input\', function(e) {\r\n                this.value = this.value.replace(/[^0-9]/g, \'\');\r\n            });\r\n        });\r\n\r\n        // 폼 제출 시 처리\r\n        document.querySelectorAll(\'form[id^="consultForm"]\').forEach(form => {\r\n            form.addEventListener(\'submit\', function(e) {\r\n                const formData = new FormData(this);\r\n                const data = {};\r\n                formData.forEach((value, key) => {\r\n                    data[key] = value;\r\n                });\r\n\r\n                // 2천만원 미만 체크\r\n                if (data[\'inputted2\'] === \'2천만 원 미만\') {\r\n                    e.preventDefault();\r\n                    alert(\'죄송합니다. 2천만 원 미만 선택 시 신청 할 수 없습니다.\');\r\n                    return false;\r\n                }\r\n                \r\n                // 담보대출 체크\r\n                if (data[\'inputted3\'] === \'담보대출 (주택 · 아파트)\') {\r\n                    e.preventDefault();\r\n                    alert(\'죄송합니다. 담보 대출 선택 시 신청 할 수 없습니다.\');\r\n                    return false;\r\n                }\r\n                \r\n                //메타 스크립트          \r\n                if (typeof fbq === \'function\') {\r\n                    fbq(\'track\', \'CompleteRegistration\');\r\n                }\r\n        \r\n\r\n            });\r\n        });\r\n\r\n        // document.querySelectorAll(\'form[id^="consultForm"]\').forEach(form => {\r\n        //     form.addEventListener(\'submit\', function(e) {\r\n        //         e.preventDefault(); // 기본 제출 막기\r\n                \r\n        //         const formData = new FormData(this);\r\n        //         const data = {};\r\n        //         formData.forEach((value, key) => {\r\n        //             data[key] = value;\r\n        //         });\r\n\r\n        //         // 2천만원 미만 체크\r\n        //         if (data[\'inputted2\'] === \'2천만 원 미만\') {\r\n        //             alert(\'죄송합니다. 2천만 원 미만 선택 시 신청 할 수 없습니다.\');\r\n        //             return false;\r\n        //         }\r\n                \r\n        //         // 담보대출 체크\r\n        //         if (data[\'inputted3\'] === \'담보대출 (주택 · 아파트)\') {\r\n        //             alert(\'죄송합니다. 담보 대출 선택 시 신청 할 수 없습니다.\');\r\n        //             return false;\r\n        //         }\r\n                \r\n        //         // 유효성 검사 통과 시 제출\r\n        //         const form = this;\r\n        //         fetch(form.action, {\r\n        //             method: form.method,\r\n        //             body: formData\r\n        //         }).then(() => {\r\n        //             // 제출 완료 후 현재 페이지를 complete.html로 교체 (뒤로가기 불가)\r\n        //             window.location.replace(\'https://land.custom-message.co.kr/assets/lawfirm/luda/page02/complite.html\');\r\n        //         }).catch(() => {\r\n        //             // fetch 실패 시에도 complete.html로 이동\r\n        //             window.location.replace(\'https://dbplatform.co.kr/rudyad2\');\r\n        //         });\r\n        //     });\r\n        // });\r\n        \r\n		\r\n		// 라디오 버튼 클릭 시 2천만원 미만 + 담보대출 체크\r\n        function checkDebtRestriction(formId) {\r\n            const form = document.getElementById(formId);\r\n            const debtValue = form.querySelector(\'input[name="inputted2"]:checked\')?.value;\r\n            const typeValue = form.querySelector(\'input[name="inputted3"]:checked\')?.value;\r\n            \r\n            // 2천만원 미만 체크\r\n            if (debtValue === \'2천만 원 미만\') {\r\n                alert(\'죄송합니다. 2천만 원 미만 선택 시 신청 할 수 없습니다.\');\r\n                // 선택 해제\r\n                form.querySelectorAll(\'input[name="inputted2"]\').forEach(radio => radio.checked = false);\r\n                return;\r\n            }\r\n            \r\n            // 담보대출 체크\r\n            if (typeValue === \'담보대출 (주택 · 아파트)\') {\r\n                alert(\'죄송합니다. 담보 대출 선택 시 신청 할 수 없습니다.\');\r\n                // 선택 해제\r\n                form.querySelectorAll(\'input[name="inputted3"]\').forEach(radio => radio.checked = false);\r\n                return;\r\n            }\r\n        }\r\n\r\n        // 폼 라디오 버튼에 이벤트 추가\r\n        document.querySelectorAll(\'#consultForm1-1 input[type="radio"]\').forEach(radio => {\r\n            radio.addEventListener(\'change\', function() {\r\n                checkDebtRestriction(\'consultForm1-1\');\r\n            });\r\n        });\r\n        \r\n        // 페이지 로드 시 뒤로가기로 온 경우 폼 초기화\r\n        window.addEventListener(\'pageshow\', function(event) {\r\n            if (event.persisted || (window.performance && window.performance.navigation.type === 2)) {\r\n                // 뒤로가기로 온 경우 모든 폼 초기화\r\n                document.querySelectorAll(\'form\').forEach(form => {\r\n                    form.reset();\r\n                });\r\n                \r\n                // 현재 상태를 초기 상태로 리셋\r\n                currentState1 = 0;\r\n                updateSection1();\r\n            }\r\n        });\r\n        \r\n        // 터치 슬라이드 기능\r\n        let touchStartX = 0;\r\n        let touchEndX = 0;\r\n        const swipeThreshold = 50; // 최소 스와이프 거리 (픽셀)\r\n        \r\n        const sectionContainer = document.getElementById(\'section1\');\r\n        \r\n        sectionContainer.addEventListener(\'touchstart\', function(e) {\r\n            touchStartX = e.changedTouches[0].screenX;\r\n        }, { passive: true });\r\n        \r\n        sectionContainer.addEventListener(\'touchend\', function(e) {\r\n            touchEndX = e.changedTouches[0].screenX;\r\n            handleSwipe();\r\n        }, { passive: true });\r\n        \r\n        // 마우스 드래그 지원 (데스크톱)\r\n        let mouseStartX = 0;\r\n        let mouseEndX = 0;\r\n        let isDragging = false;\r\n        \r\n        sectionContainer.addEventListener(\'mousedown\', function(e) {\r\n            isDragging = true;\r\n            mouseStartX = e.screenX;\r\n        });\r\n        \r\n        sectionContainer.addEventListener(\'mousemove\', function(e) {\r\n            if (isDragging) {\r\n                mouseEndX = e.screenX;\r\n            }\r\n        });\r\n        \r\n        sectionContainer.addEventListener(\'mouseup\', function(e) {\r\n            if (isDragging) {\r\n                mouseEndX = e.screenX;\r\n                handleSwipe(true);\r\n                isDragging = false;\r\n            }\r\n        });\r\n        \r\n        sectionContainer.addEventListener(\'mouseleave\', function(e) {\r\n            if (isDragging) {\r\n                isDragging = false;\r\n            }\r\n        });\r\n        \r\n        function handleSwipe(isMouse = false) {\r\n            const startX = isMouse ? mouseStartX : touchStartX;\r\n            const endX = isMouse ? mouseEndX : touchEndX;\r\n            const diff = startX - endX;\r\n            \r\n            // 스와이프 거리가 임계값보다 작으면 무시\r\n            if (Math.abs(diff) < swipeThreshold) {\r\n                return;\r\n            }\r\n            \r\n            // 왼쪽으로 스와이프 (다음)\r\n            if (diff > 0) {\r\n                // 폼 화면(currentState1 === 2)에서 다음으로 가려면 유효성 검사 필요\r\n                if (currentState1 === 2) {\r\n                    const form = document.getElementById(\'consultForm1-1\');\r\n                    if (!form.checkValidity()) {\r\n                        form.reportValidity();\r\n                        return;\r\n                    }\r\n                    // 폼 데이터 저장\r\n                    saveFormData1();\r\n                }\r\n                navigate1(1);\r\n            }\r\n            // 오른쪽으로 스와이프 (이전)\r\n            else if (diff < 0) {\r\n                navigate1(-1);\r\n            }\r\n        }\r\n		\r\n    </script>\r\n</body>\r\n</html>', '2', NULL, '', '', 'Y', '2026-04-16 11:23:10', '2026-04-23 21:09:59', 'cstmsg', 'cstmsg', '이동기', '이동기'),
	(3, '루다법무사1', '루다법무사1', 1, 3, NULL, '<!DOCTYPE html>\r\n<html lang="ko">\r\n<head>\r\n    <meta charset="UTF-8">\r\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\r\n    <title>루다법무사 - 개인회생 상담</title>\r\n    <link rel="preconnect" href="https://fonts.googleapis.com">\r\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\r\n    <link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@400;500;700;900&family=Black+Han+Sans&display=swap" rel="stylesheet">\r\n    <style>\r\n        * {\r\n            margin: 0;\r\n            padding: 0;\r\n            box-sizing: border-box;\r\n        }\r\n\r\n        body {\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            background: #f5f5f5;\r\n            margin: 0;\r\n            padding: 0;\r\n        }\r\n\r\n        .container {\r\n            max-width: 800px;\r\n            margin: 0 auto;\r\n            background: white;\r\n        }\r\n\r\n        .header-image {\r\n            width: 100%;\r\n            display: block;\r\n        }\r\n\r\n        /* 03 이미지 스타일 - 네이비 블루 헤더 */\r\n        .form-header {\r\n            background: linear-gradient(180deg, #1e3a8a 0%, #1e40af 100%);\r\n            padding: 40px 20px;\r\n            text-align: center;\r\n            color: white;\r\n        }\r\n\r\n        .form-header h1 {\r\n            font-size: 32px;\r\n            font-weight: 900;\r\n            margin-bottom: 10px;\r\n            line-height: 1.3;\r\n        }\r\n\r\n        .form-header h2 {\r\n            font-size: 28px;\r\n            font-weight: 700;\r\n            color: #fbbf24;\r\n            margin: 0;\r\n        }\r\n\r\n        /* 폼 섹션 - 밝은 회색 배경 */\r\n        .form-section {\r\n            background: #e5e7eb;\r\n            padding: 50px 30px;\r\n        }\r\n\r\n        .form-group {\r\n            margin-bottom: 40px;\r\n        }\r\n\r\n        .form-label {\r\n            display: flex;\r\n            align-items: center;\r\n            font-size: 22px;\r\n            font-weight: 700;\r\n            color: #1f2937;\r\n            margin-bottom: 20px;\r\n        }\r\n\r\n        .form-label::before {\r\n            content: \'◆\';\r\n            margin-right: 10px;\r\n            color: #1f2937;\r\n            font-size: 18px;\r\n        }\r\n\r\n        /* 라디오 버튼 스타일 - 03 이미지처럼 */\r\n        .radio-group {\r\n            display: flex;\r\n            flex-direction: column;\r\n            gap: 15px;\r\n        }\r\n\r\n        .radio-option {\r\n            display: flex;\r\n            align-items: center;\r\n        }\r\n\r\n        .radio-option input[type="radio"] {\r\n            width: 24px;\r\n            height: 24px;\r\n            margin-right: 12px;\r\n            cursor: pointer;\r\n            accent-color: #1e3a8a;\r\n        }\r\n\r\n        .radio-label {\r\n            font-size: 20px;\r\n            font-weight: 500;\r\n            color: #374151;\r\n            cursor: pointer;\r\n        }\r\n\r\n        \r\n\r\n        /* 작은 빨간 텍스트 */\r\n        .info-text {\r\n            color: #dc2626;\r\n            font-size: 16px;\r\n            margin-top: 15px;\r\n            line-height: 1.6;\r\n        }\r\n\r\n        /* 입력 필드 */\r\n        .input-field {\r\n            width: 100%;\r\n            padding: 15px;\r\n            border: 2px solid #d1d5db;\r\n            border-radius: 4px;\r\n            font-size: 18px;\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            background: white;\r\n        }\r\n\r\n        .input-field:focus {\r\n            outline: none;\r\n            border-color: #1e3a8a;\r\n        }\r\n\r\n        .tel-group {\r\n            display: grid;\r\n            grid-template-columns: 100px 1fr 1fr;\r\n            gap: 10px;\r\n        }\r\n\r\n        .tel-fixed {\r\n            background: #f3f4f6;\r\n            color: #6b7280;\r\n            cursor: not-allowed;\r\n        }\r\n\r\n        select.input-field {\r\n            cursor: pointer;\r\n        }\r\n\r\n        textarea.input-field {\r\n            min-height: 120px;\r\n            resize: vertical;\r\n        }\r\n\r\n        .submit-btn {\r\n            width: 100%;\r\n            padding: 20px;\r\n            background: #1e3a8a;\r\n            color: white;\r\n            border: none;\r\n            border-radius: 4px;\r\n            font-size: 20px;\r\n            font-weight: 700;\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            cursor: pointer;\r\n            margin-top: 30px;\r\n        }\r\n\r\n        .submit-btn:hover {\r\n            background: #1e40af;\r\n        }\r\n\r\n        .submit-btn:active {\r\n            background: #1e3a8a;\r\n        }\r\n\r\n        /* 반응형 */\r\n        @media (max-width: 768px) {\r\n            .form-header h1 {\r\n                font-size: 24px;\r\n            }\r\n\r\n            .form-header h2 {\r\n                font-size: 22px;\r\n            }\r\n\r\n            .form-section {\r\n                padding: 30px 20px;\r\n            }\r\n\r\n            .form-label {\r\n                font-size: 18px;\r\n            }\r\n\r\n            .radio-label,\r\n            .checkbox-label {\r\n                font-size: 16px;\r\n            }\r\n\r\n            .tel-group {\r\n                grid-template-columns: 80px 1fr 1fr;\r\n            }\r\n        }\r\n		\r\n		        /* footer */\r\n        .site-footer {\r\n            background: #111827;\r\n            color: #e5e7eb;\r\n            padding: 32px 24px 40px;\r\n            border-top: 4px solid #1e3a8a;\r\n        }\r\n\r\n        .footer-inner {\r\n            max-width: 800px;\r\n            margin: 0 auto;\r\n        }\r\n\r\n        .footer-title {\r\n            font-size: 22px;\r\n            font-weight: 800;\r\n            color: #ffffff;\r\n            margin-bottom: 18px;\r\n            letter-spacing: -0.3px;\r\n        }\r\n\r\n        .footer-info {\r\n            display: flex;\r\n            flex-direction: column;\r\n            gap: 10px;\r\n        }\r\n\r\n        .footer-row {\r\n            display: flex;\r\n            flex-wrap: wrap;\r\n            gap: 8px;\r\n            font-size: 15px;\r\n            line-height: 1.7;\r\n            color: #d1d5db;\r\n        }\r\n\r\n        .footer-label {\r\n            font-weight: 700;\r\n            color: #9ca3af;\r\n            min-width: 110px;\r\n        }\r\n\r\n        .footer-value {\r\n            flex: 1;\r\n            min-width: 0;\r\n            color: #f3f4f6;\r\n            word-break: keep-all;\r\n        }\r\n\r\n        .footer-copy {\r\n            margin-top: 22px;\r\n            padding-top: 18px;\r\n            border-top: 1px solid rgba(255, 255, 255, 0.12);\r\n            font-size: 13px;\r\n            color: #9ca3af;\r\n            line-height: 1.6;\r\n        }\r\n\r\n        @media (max-width: 768px) {\r\n            .site-footer {\r\n                padding: 26px 18px 32px;\r\n            }\r\n\r\n            .footer-title {\r\n                font-size: 18px;\r\n                margin-bottom: 14px;\r\n            }\r\n\r\n            .footer-row {\r\n                flex-direction: column;\r\n                gap: 2px;\r\n                font-size: 14px;\r\n            }\r\n\r\n            .footer-label {\r\n                min-width: auto;\r\n            }\r\n\r\n            .footer-copy {\r\n                font-size: 12px;\r\n            }\r\n        }\r\n		\r\n    </style>\r\n</head>\r\n<body>\r\n    <div class="container">\r\n        <!-- 상단 GIF 이미지 -->\r\n        <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page01/01_mz%20%ED%9A%8C%EC%83%9D.gif" alt="루다법무사 개인회생" class="header-image">\r\n        \r\n        <!-- 두번째 이미지 -->\r\n        <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page01/02_mz%20%ED%9A%8C%EC%83%9D.jpg" alt="개인회생 안내" class="header-image">\r\n\r\n        <!-- 상담 신청 폼 -->\r\n        <div class="form-header">\r\n            <h1>상담 = 신청 아닙니다</h1>\r\n            <h2>먼저 답답함을 확인해보세요</h2>\r\n        </div>\r\n\r\n        <div class="form-section">\r\n            <form id="consultForm" action="submit.html" method="POST">\r\n                <!-- 현재 당감이 필요한 빚은 얼마인가요 -->\r\n                <div class="form-group">\r\n                    <label class="form-label">현재 당감이 필요한 빚은 얼마인가요?</label>\r\n                    <div class="radio-group">\r\n                        <div class="radio-option">\r\n                            <input type="radio" id="debt1" name="inputted2" value="2천만 원 미만" required>\r\n                            <label for="debt1" class="radio-label">2천만 원 미만</label>\r\n                        </div>\r\n                        <div class="radio-option">\r\n                            <input type="radio" id="debt2" name="inputted2" value="2천만 원 ~ 5천만 원">\r\n                            <label for="debt2" class="radio-label">2천만 원 ~ 5천만 원</label>\r\n                        </div>\r\n                        <div class="radio-option">\r\n                            <input type="radio" id="debt3" name="inputted2" value="5천만 원 ~ 8천만 원">\r\n                            <label for="debt3" class="radio-label">5천만 원 ~ 8천만 원</label>\r\n                        </div>\r\n                        <div class="radio-option">\r\n                            <input type="radio" id="debt4" name="inputted2" value="8천만 원 ~ 1억 원 미만">\r\n                            <label for="debt4" class="radio-label">8천만 원 ~ 1억 원 미만</label>\r\n                        </div>\r\n                        <div class="radio-option">\r\n                            <input type="radio" id="debt5" name="inputted2" value="1억 원 이상">\r\n                            <label for="debt5" class="radio-label">1억 원 이상</label>\r\n                        </div>\r\n                    </div>\r\n                    <p class="info-text">(신용대출·카드빚·코인·주식 채무가 2천만 원 이상이면<br>개인회생이 가능한 경우가 대부분입니다)</p>\r\n                <