n                        <input type="text" name="tel2" class="input-field" placeholder="1234" maxlength="4" pattern="[0-9]{3,4}" required>\r\n                        <input type="text" name="tel3" class="input-field" placeholder="5678" maxlength="4" pattern="[0-9]{4}" required>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- 상담가능시간 -->\r\n                <div class="form-group">\r\n                    <label class="form-label">상담 가능 시간</label>\r\n                    <select name="inputted1" class="input-field" required>\r\n                        <option value="">선택해주세요</option>\r\n                        <option value="오전">오전 (09:00 - 12:00)</option>\r\n                        <option value="점심">점심 (12:00 - 14:00)</option>\r\n                        <option value="오후">오후 (14:00 - 18:00)</option>\r\n                    </select>\r\n                </div>\r\n\r\n                <!-- 상담메모 -->\r\n                <div class="form-group">\r\n                    <label class="form-label">상담 메모</label>\r\n                    <textarea name="inputted5" class="input-field" placeholder="상담받고 싶은 내용을 자유롭게 작성해주세요 (선택사항)"></textarea>\r\n                </div>\r\n\r\n                <!-- 개인정보 동의 -->\r\n                <div class="form-group" style="display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 10px;">\r\n                    <label style="display: flex; align-items: center; cursor: pointer; flex: 1;">\r\n                        <input type="checkbox" required style="width: 20px; height: 20px; margin-right: 10px; cursor: pointer;">\r\n                        <span style="font-size: 16px; color: #333;">개인정보 수집 및 상담 연락에 동의합니다. (필수)</span>\r\n                    </label>\r\n                    <button type="button" onclick="openPrivacyModal()" style="padding: 8px 16px; background: #666; color: white; border: none; border-radius: 4px; font-size: 14px; cursor: pointer;">약관 보기</button>\r\n                </div>\r\n\r\n                <!-- 제출 버튼 -->\r\n                <button type="submit" class="submit-btn">무료 상담 신청하기</button>\r\n            </form>\r\n        </div>\r\n		\r\n		<!-- 9 이미지 -->\r\n        <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page01/06_mz%20%ED%9A%8C%EC%83%9D.jpg" alt="상담 안내" class="header-image">\r\n		\r\n		<!-- 10 이미지 -->\r\n        <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page01/07_mz%20%ED%9A%8C%EC%83%9D.jpg" alt="상담 안내" class="header-image">\r\n\r\n        \r\n    </div>\r\n	\r\n	<footer class="site-footer">\r\n		<div class="footer-inner">\r\n			<div class="footer-title">루다 합동법무사사무소</div>\r\n\r\n			<div class="footer-info">\r\n				<div class="footer-row">\r\n					<span class="footer-label">사업자등록번호</span>\r\n					<span class="footer-value">209-44-91325</span>\r\n				</div>\r\n\r\n				<div class="footer-row">\r\n					<span class="footer-label">대표</span>\r\n					<span class="footer-value">김현기</span>\r\n				</div>\r\n\r\n				<div class="footer-row">\r\n					<span class="footer-label">주소</span>\r\n					<span class="footer-value">서울시 강남구 테헤란로21길 5, 10층(역삼동, 이너스타워)</span>\r\n				</div>\r\n			</div>\r\n\r\n			<div class="footer-copy">\r\n				© 루다 합동법무사사무소. All rights reserved.\r\n			</div>\r\n		</div>\r\n	</footer>\r\n	\r\n\r\n    <!-- 개인정보 약관 모달 -->\r\n    <div id="privacyModal" style="display: none; position: fixed; z-index: 9999; left: 0; top: 0; width: 100%; height: 100%; background: rgba(0, 0, 0, 0.6); align-items: center; justify-content: center;">\r\n		<div style="background: white; padding: 30px; border-radius: 16px; max-width: 600px; width: 90%; max-height: 80vh; overflow-y: auto; box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);">\r\n			<div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; padding-bottom: 15px; border-bottom: 2px solid #eee;">\r\n				<h3 style="font-size: 22px; font-weight: 700; color: #333; margin: 0;">개인정보 처리방침</h3>\r\n				<button onclick="closePrivacyModal()" style="background: none; border: none; font-size: 28px; cursor: pointer; color: #999; width: 36px; height: 36px; display: flex; align-items: center; justify-content: center; border-radius: 50%;">&times;</button>\r\n			</div>\r\n			<div style="font-size: 14px; line-height: 1.8; color: #555;">\r\n				<p>루다법무사사무소(이하 "본 법무사사무소"라고 함)은 「개인정보 보호법」 제30조에 따라 정보주체의 개인정보를 보호하고 이와 관련한 고충을 신속하고 원활하게 처리할 수 있도록 하기 위하여 다음과 같이 개인정보 처리방침을 수립·공개합니다.</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제1조(개인정보의 처리목적)</h4>\r\n				<p>본 법무사사무소가 개인정보 보호법 제32조에 따라 등록․공개하는 개인정보파일의 처리목적은 다음과 같습니다.</p>\r\n				<p>\r\n					- 개인정보 파일명 : 인적사항<br>\r\n					- 개인정보의 처리목적 : 법률 서비스 제공<br>\r\n					- 수집방법 : 생성정보 수집 툴을 통한 수집, 전화/팩스, 서면양식, 홈페이지<br>\r\n					- 보유근거 : 통신비밀보호법 등<br>\r\n					- 보유기간 : 준영구<br>\r\n					- 관련법령 : 표시/광고에 관한 기록 : 6개월, 계약 또는 청약철회 등에 관한 기록 : 5년, 대금결제 및 재화 등의 공급에 관한 기록 : 5년, 소비자의 불만 또는 분쟁처리에 관한 기록 : 3년, 신용정보의 수집/처리 및 이용 등에 관한 기록 : 3년\r\n				</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제2조(처리하는 개인정보의 항목)</h4>\r\n				<p>인적사항<br>\r\n					- 필수항목 : 이름, 휴대전화번호, 접속 로그, 상담신청 절차에서 발생된 정보<br>\r\n					- 선택항목 : \r\n				</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제3조(개인정보의 파기절차 및 파기방법)</h4>\r\n				<p>본 법무사사무소는 개인정보 보유기간의 경과, 처리목적 달성 등 개인정보가 불필요하게 되었을 때에는 지체없이 해당 개인정보를 파기합니다.<br>\r\n					개인정보 파기의 절차 및 방법은 다음과 같습니다.<br>\r\n					- 파기절차: 본 법무사사무소는 파기 사유가 발생한 개인정보를 선정하고, 본 법무사사무소의 개인정보 보호책임자의 승인을 받아 개인정보를 파기합니다.<br>\r\n					- 파기방법: 종이에 출력된 개인정보는 분쇄기로 분쇄하거나 소각을 통하여 파기합니다.\r\n				</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제4조(개인정보주체의 권리·의무 및 그 행사방법)</h4>\r\n				<p>(1) 정보주체는 관계 법령이 정하는 바에 따라 개인정보의 열람, 정정·삭제, 처리정지 및 동의 철회 등 개인정보 보호 관련 권리를 행사할 수 있습니다. 이 경우 본 법무사사무소는 정정 또는 삭제 등의 조치를 완료할 때까지 당해 개인정보를 이용하거나 제공지 않습니다.<br>\r\n					(2) 제1항에 따른 권리행사는 본 법무사사무소에 대하여 개인정보 보호법 시행규칙 별지 제8호 서식에 따라 서면, 전자우편, 모사전송(FAX) 등을 통하여 하실 수 있습니다.<br>\r\n					(3) 제1항의 따른 권리행사는 정보주체의 법정대리인을 통해서도 행사할 수 있으며, 이 경우에는 개인정보 보호법 시행규칙 별지 제11호 서식에 따른 위임장을 본 법무사사무소에 제출해야 합니다.<br>\r\n					(4) 본 법무사사무소는 정보주체의 권리행사에 관하여 관계 법령이 정하는 바에 따라 지체없이 조치하겠습니다.\r\n				</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제5조(개인정보의 파기)</h4>\r\n				<p>(1) 본 법무사사무소는 제1조에 따른 개인정보의 보유기간이 경과된 경우에는 정당한 사유가 없는 한 보유기간의 종료일로부터 5일 이내에, 개인정보의 처리 목적 달성 등 그 개인정보가 불필요하게 되었을 때에는 정당한 사유가 없는 한 개인정보의 처리가 필요한 것으로 인정되는 날로부터 5일 이내에 그 개인정보를 파기합니다.<br>\r\n					(2) 본 법무사사무소는 관계법령의 규정에 의하여 보존할 필요가 있는 경우 해당 개인정보 또는 개인정보파일을 다른 개인정보와 분리해서 저장·관리 합니다.<br>\r\n					(3) 본 법무사사무소는 개인정보보호 책임자의 승인을 받아 개인정보를 파기합니다.<br>\r\n					(4) 개인정보가 기록된 출력물, 서면 등은 파쇄 또는 소각의 방법으로 파기하고, 전자파일 형태의 개인정보는 복원이 불가능한 방법으로 영구 삭제하는 방법으로 파기합니다.<br>\r\n					(5) 게시물의 경우 정보주체가 본인의 게시물을 삭제하지 않는 한 본 법무사사무소는 해당 게시물에 담겨 있는 개인정보를 계속적으로 보유합니다. 다만, 정보주체는 본인의 게시물을 언제든 삭제할 수 있으며 정보주체에 의한 게시물 삭제 이후에는 게시물 이에 담겨있는 개인정보는 추후 열람이 불가능한 상태로 처리됩니다.\r\n				</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제6조(개인정보의 안전성 확보조치)</h4>\r\n				<p>(1)본 법무사사무소는 관계 법령에 따라 다음 각 호와 같이 안전성 확보조치를 취하고 있습니다.<br>\r\n					가. 물리적 보호조치 : 전산실, 자료실 등에 개인정보 보관 장소에 대한 접근통제<br>\r\n					나. 관리적 보호조치 : 내부관리계획의 수립 및 시행, 정기적인 개인정보 보호 교육<br>\r\n					다. 기술적 보호조치 : 개인정보처리시스템에 대한 접근통제, 접근권한 관리, 보안 프로그램의 설치 및 암호화\r\n				</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제7조 (개인정보 보호책임자에 관한 사항)</h4>\r\n				<p>본 법무사사무소는 개인정보 처리에 관한 업무를 총괄해서 책임지고, 개인정보 처리와 관련한 정보주체의 불만처리 및 피해구제 등을 위하여 아래와 같이 개인정보 보호책임자를 지정하고 있습니다.<br>\r\n					▶ 개인정보 보호책임자<br>\r\n					성명 : 김현기<br>\r\n					직책 : 대표 법무사<br>\r\n					연락처 : 02-6385-7000\r\n				</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제8조(개인정보 처리방침의 변경)</h4>\r\n				<p>본 법무사사무소의 개인정보처리방침은 변경될 수 있으며, 개인정보처리방침이 변경되는 경우 법령이 정한 방법에 따라 공개합니다.</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제9조(권익침해 구제방법)</h4>\r\n				<p>정보주체는 아래의 기관에 대해 개인정보 침해에 대한 피해구제, 상담 등을 문의하실 수 있습니다.<br>\r\n					※ 개인정보 침해신고센터 (한국인터넷진흥원 운영): privacy.kisa.or.kr / (국번없이) 118<br>\r\n					※ 개인정보분쟁조정위원회: kopico.go.kr / 1833-6972<br>\r\n					※ 대검찰청 사이버수사과: spo.go.kr / (국번없이) 1301<br>\r\n					※ 경찰청 사이버안전국: cyberbureau.police.go.kr / (국번없이) 182\r\n				</p>\r\n\r\n				<h4 style="font-size: 16px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제10조(개인정보 처리방침 변경)</h4>\r\n				<p>이 개인정보처리방침은 2026년 04월 20일부터 적용됩니다.</p>\r\n			</div>\r\n		</div>\r\n	</div>\r\n\r\n    <script>\r\n        // 개인정보 약관 모달\r\n        function openPrivacyModal() {\r\n            const modal = document.getElementById(\'privacyModal\');\r\n            modal.style.display = \'flex\';\r\n            document.body.style.overflow = \'hidden\';\r\n        }\r\n\r\n        function closePrivacyModal() {\r\n            const modal = document.getElementById(\'privacyModal\');\r\n            modal.style.display = \'none\';\r\n            document.body.style.overflow = \'auto\';\r\n        }\r\n\r\n        // 모달 배경 클릭 시 닫기\r\n        document.getElementById(\'privacyModal\').addEventListener(\'click\', function(e) {\r\n            if (e.target === this) {\r\n                closePrivacyModal();\r\n            }\r\n        });\r\n\r\n        // 전화번호 입력 시 자동 포커스 이동\r\n        document.querySelectorAll(\'input[name="tel2"]\').forEach(input => {\r\n            input.addEventListener(\'input\', function(e) {\r\n                if (this.value.length === 4) {\r\n                    const tel3 = this.parentElement.querySelector(\'input[name="tel3"]\');\r\n                    if (tel3) tel3.focus();\r\n                }\r\n            });\r\n        });\r\n\r\n        // 숫자만 입력 가능하도록\r\n        document.querySelectorAll(\'input[name="tel2"], input[name="tel3"]\').forEach(input => {\r\n            input.addEventListener(\'input\', function(e) {\r\n                this.value = this.value.replace(/[^0-9]/g, \'\');\r\n            });\r\n        });\r\n\r\n        // 폼 제출 시 처리\r\n		document.querySelectorAll(\'form\').forEach(form => {\r\n			form.addEventListener(\'submit\', function(e) {\r\n				// 우선 기본 동작을 막아 조건 검사를 진행합니다.\r\n				const formData = new FormData(this);\r\n				const data = {};\r\n				formData.forEach((value, key) => {\r\n					data[key] = value;\r\n				});\r\n\r\n				// //추가: 2천만원 미만 + 담보대출 체크 로직\r\n				if (data[\'inputted2\'] === \'2천만 원 미만\' && data[\'inputted3\'] === \'담보대출 (주택 · 아파트)\') {\r\n					e.preventDefault(); // 조건에 걸리면 제출 차단\r\n					alert(\'죄송합니다. 2천만 원 미만, 담보 대출 선택 시 신청 할 수 없습니다.\');\r\n					return false;\r\n				}\r\n				\r\n				// 조건 통과 시:\r\n				// 만약 AJAX가 아닌 PHP(submit.html)로 직접 화면을 넘기려면 \r\n				// 아래 e.preventDefault()를 실행하지 않아야 합니다.\r\n				\r\n				// alert(\'상담 신청을 진행합니다.\'); // 확인용 알림 (필요없으면 삭제)\r\n				\r\n				// 주의: 여기서 e.preventDefault()를 쓰지 않으면 action="submit.html"로 데이터가 전송됩니다.\r\n			});\r\n		});\r\n    </script>\r\n</body>\r\n</html>', '2', '2', '', '', 'Y', '2026-04-15 12:22:57', '2026-04-23 21:09:59', 'cstmsg', 'cstmsg', 'cstmsg', '이동기'),
	(4, '루디법무사3', '루디법무사3', 1, 3, 1, '<!DOCTYPE html>\r\n<html lang="ko">\r\n<head>\r\n    <meta charset="UTF-8">\r\n    <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">\r\n    <title>루다법무사 - 청년회생 상담</title>\r\n    <link rel="preconnect" href="https://fonts.googleapis.com">\r\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\r\n    <link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@400;500;700;900&display=swap" rel="stylesheet">\r\n    <style>\r\n        * {\r\n            margin: 0;\r\n            padding: 0;\r\n            box-sizing: border-box;\r\n        }\r\n\r\n        body {\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            margin: 0;\r\n            padding: 0;\r\n            overflow: hidden;\r\n            width: 100%;\r\n            height: 100vh;\r\n        }\r\n\r\n        .page-container {\r\n            position: relative;\r\n            width: 100%;\r\n            max-width: 800px;\r\n            height: 100vh;\r\n            margin: 0 auto;\r\n            background: white;\r\n            overflow: hidden;\r\n        }\r\n\r\n        /* 배경 이미지들 (찢어진 후 보일 내용) */\r\n        .background-images {\r\n            position: absolute;\r\n            top: 0;\r\n            left: 0;\r\n            width: 100%;\r\n            height: 100%;\r\n            overflow-y: auto;\r\n            z-index: 1;\r\n        }\r\n\r\n        .background-images img {\r\n            width: 100%;\r\n            height: auto;\r\n            display: block;\r\n        }\r\n\r\n        /* 찢어지는 빚 이미지 레이어 */\r\n        .tear-layer {\r\n            position: absolute;\r\n            top: 0;\r\n            left: 0;\r\n            width: 100%;\r\n            height: 100%;\r\n            z-index: 10;\r\n            pointer-events: none;\r\n        }\r\n\r\n        /* 왼쪽 반쪽 */\r\n        .tear-left {\r\n            position: absolute;\r\n            top: 0;\r\n            left: 0;\r\n            width: 50%;\r\n            height: 100%;\r\n            background-image: url(\'https://land.custom-message.co.kr/assets/lawfirm/luda/page03/00_%EB%B9%9A%EB%A1%9C%EB%94%A9.png\');\r\n            background-size: 200% 100vh;\r\n            background-position: left center;\r\n            background-repeat: no-repeat;\r\n            transition: transform 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55);\r\n            clip-path: polygon(0 0, 100% 0, 100% 100%, 0 100%);\r\n            pointer-events: auto;\r\n        }\r\n\r\n        .tear-left.torn {\r\n            transform: translateX(-100%) rotate(-5deg);\r\n        }\r\n\r\n        /* 오른쪽 반쪽 */\r\n        .tear-right {\r\n            position: absolute;\r\n            top: 0;\r\n            right: 0;\r\n            width: 50%;\r\n            height: 100%;\r\n            background-image: url(\'https://land.custom-message.co.kr/assets/lawfirm/luda/page03/00_%EB%B9%9A%EB%A1%9C%EB%94%A9.png\');\r\n            background-size: 200% 100vh;\r\n            background-position: right center;\r\n            background-repeat: no-repeat;\r\n            transition: transform 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55);\r\n            clip-path: polygon(0 0, 100% 0, 100% 100%, 0 100%);\r\n            pointer-events: auto;\r\n        }\r\n\r\n        .tear-right.torn {\r\n            transform: translateX(100%) rotate(5deg);\r\n        }\r\n\r\n        /* 가위 애니메이션 */\r\n        .scissors {\r\n            position: absolute;\r\n            top: 50%;\r\n            left: 50%;\r\n            transform: translate(-50%, -50%);\r\n            font-size: 80px;\r\n            z-index: 100;\r\n            animation: scissorCut 2s ease-in-out infinite;\r\n            pointer-events: none;\r\n            filter: drop-shadow(0 4px 12px rgba(0, 0, 0, 0.4));\r\n        }\r\n\r\n        @keyframes scissorCut {\r\n            0%, 100% {\r\n                transform: translate(-50%, -50%) translateY(-30px) rotate(0deg);\r\n            }\r\n            50% {\r\n                transform: translate(-50%, -50%) translateY(30px) rotate(15deg);\r\n            }\r\n        }\r\n\r\n        .scissors.hidden {\r\n            display: none;\r\n        }\r\n\r\n        /* 클릭 영역 */\r\n        .click-area {\r\n            position: absolute;\r\n            top: 0;\r\n            left: 0;\r\n            width: 100%;\r\n            height: 100%;\r\n            z-index: 50;\r\n            cursor: pointer;\r\n        }\r\n\r\n        .click-area.hidden {\r\n            display: none;\r\n        }\r\n\r\n        /* 폼 페이지 */\r\n        .form-page {\r\n            position: relative;\r\n            width: 100%;\r\n            background: linear-gradient(135deg, #f5f7fa 0%, #ffffff 100%);\r\n            padding: 40px 20px;\r\n        }\r\n\r\n        .form-container {\r\n            max-width: 600px;\r\n            margin: 0 auto;\r\n            background: white;\r\n            padding: 40px;\r\n            border-radius: 20px;\r\n            box-shadow: 0 10px 40px rgba(0, 0, 0, 0.08);\r\n        }\r\n\r\n        .form-title {\r\n            text-align: center;\r\n            margin-bottom: 30px;\r\n        }\r\n\r\n        .form-title h2 {\r\n            font-size: 45px;\r\n            font-weight: 900;\r\n            color: #1f2937;\r\n            margin-bottom: 10px;\r\n            background: linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%);\r\n            -webkit-background-clip: text;\r\n            -webkit-text-fill-color: transparent;\r\n            background-clip: text;\r\n        }\r\n\r\n        .form-title p {\r\n            font-size: 17px;\r\n            font-weight: 600;\r\n            background: linear-gradient(\r\n                90deg,\r\n                #ff0000 0%,    /* 빨강 */\r\n                #ff7f00 14%,   /* 주황 */\r\n                #ffff00 28%,   /* 노랑 */\r\n                #00ff00 42%,   /* 초록 */\r\n                #0000ff 57%,   /* 파랑 */\r\n                #4b0082 71%,   /* 남색 */\r\n                #9400d3 85%,   /* 보라 */\r\n                #ff0000 100%   /* 빨강 (반복) */\r\n            );\r\n            background-size: 200% 100%;\r\n            -webkit-background-clip: text;\r\n            -webkit-text-fill-color: transparent;\r\n            background-clip: text;\r\n            animation: rainbow 3s linear infinite;\r\n        }\r\n\r\n        @keyframes rainbow {\r\n            0% {\r\n                background-position: 0% 50%;\r\n            }\r\n            100% {\r\n                background-position: 200% 50%;\r\n            }\r\n        }\r\n\r\n        .form-group {\r\n            margin-bottom: 20px;\r\n        }\r\n\r\n        .form-label {\r\n            display: block;\r\n            font-size: 15px;\r\n            font-weight: 700;\r\n            color: #374151;\r\n            margin-bottom: 10px;\r\n            padding-left: 10px;\r\n            position: relative;\r\n        }\r\n\r\n        .form-label::before {\r\n            content: \'\';\r\n            position: absolute;\r\n            left: 0;\r\n            top: 50%;\r\n            transform: translateY(-50%);\r\n            width: 3px;\r\n            height: 16px;\r\n            background: linear-gradient(135deg, #3b82f6, #8b5cf6);\r\n            border-radius: 2px;\r\n        }\r\n\r\n        .radio-group {\r\n            display: flex;\r\n            flex-direction: column;\r\n            gap: 10px;\r\n        }\r\n\r\n        .radio-option {\r\n            display: flex;\r\n            align-items: center;\r\n            padding: 12px 16px;\r\n            background: #f9fafb;\r\n            border: 2px solid #e5e7eb;\r\n            border-radius: 10px;\r\n            cursor: pointer;\r\n            transition: all 0.3s;\r\n        }\r\n\r\n        .radio-option:hover {\r\n            background: #f3f4f6;\r\n            border-color: #3b82f6;\r\n        }\r\n\r\n        .radio-option input[type="radio"] {\r\n            width: 18px;\r\n            height: 18px;\r\n            margin-right: 10px;\r\n            cursor: pointer;\r\n            accent-color: #3b82f6;\r\n        }\r\n\r\n        .radio-option:has(input:checked) {\r\n            background: #eff6ff;\r\n            border-color: #3b82f6;\r\n            box-shadow: 0 4px 12px rgba(59, 130, 246, 0.2);\r\n        }\r\n\r\n        .radio-label {\r\n            font-size: 14px;\r\n            font-weight: 500;\r\n            color: #4b5563;\r\n            cursor: pointer;\r\n        }\r\n\r\n        .input-field {\r\n            width: 100%;\r\n            padding: 12px 15px;\r\n            border: 2px solid #e5e7eb;\r\n            border-radius: 10px;\r\n            font-size: 14px;\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            background: white;\r\n            transition: all 0.3s;\r\n        }\r\n\r\n        .input-field:focus {\r\n            outline: none;\r\n            border-color: #3b82f6;\r\n            box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1);\r\n        }\r\n\r\n        .tel-group {\r\n            display: grid;\r\n            grid-template-columns: 80px 1fr 1fr;\r\n            gap: 10px;\r\n        }\r\n\r\n        .tel-fixed {\r\n            background: #f3f4f6;\r\n            color: #6b7280;\r\n            cursor: not-allowed;\r\n        }\r\n\r\n        select.input-field {\r\n            cursor: pointer;\r\n        }\r\n\r\n        textarea.input-field {\r\n            min-height: 100px;\r\n            resize: vertical;\r\n        }\r\n\r\n        .submit-btn {\r\n            width: 100%;\r\n            padding: 16px;\r\n            background: linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%);\r\n            color: white;\r\n            border: none;\r\n            border-radius: 10px;\r\n            font-size: 17px;\r\n            font-weight: 700;\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            cursor: pointer;\r\n            margin-top: 20px;\r\n            transition: all 0.3s;\r\n            box-shadow: 0 4px 15px rgba(59, 130, 246, 0.3);\r\n        }\r\n\r\n        .submit-btn:hover {\r\n            transform: translateY(-2px);\r\n            box-shadow: 0 6px 20px rgba(59, 130, 246, 0.4);\r\n        }\r\n\r\n        .privacy-group {\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 10px;\r\n            padding: 12px;\r\n            background: #f9fafb;\r\n            border-radius: 10px;\r\n            margin-top: 15px;\r\n        }\r\n\r\n        .privacy-group input[type="checkbox"] {\r\n            width: 18px;\r\n            height: 18px;\r\n            cursor: pointer;\r\n            accent-color: #3b82f6;\r\n        }\r\n\r\n        .privacy-group label {\r\n            font-size: 12px;\r\n            color: #4b5563;\r\n            cursor: pointer;\r\n            flex: 1;\r\n        }\r\n\r\n        .privacy-btn {\r\n            padding: 6px 16px;\r\n            background: #6b7280;\r\n            color: white;\r\n            border: none;\r\n            border-radius: 6px;\r\n            font-size: 13px;\r\n            cursor: pointer;\r\n            transition: background 0.3s;\r\n            font-family: \'Noto Sans KR\', sans-serif;\r\n            font-weight: 500;\r\n            white-space: nowrap;\r\n        }\r\n\r\n        .privacy-btn:hover {\r\n            background: #4b5563;\r\n        }\r\n\r\n        .info-text {\r\n            color: #dc2626;\r\n            font-size: 12px;\r\n            margin-top: 10px;\r\n            line-height: 1.5;\r\n        }\r\n\r\n        @media (max-width: 768px) {\r\n            .scissors {\r\n                font-size: 60px;\r\n            }\r\n\r\n            .form-container {\r\n                padding: 30px 20px;\r\n            }\r\n\r\n            .form-title h2 {\r\n                font-size: 45px;\r\n            }\r\n\r\n            .tel-group {\r\n                grid-template-columns: 70px 1fr 1fr;\r\n            }\r\n        }\r\n        \r\n        \r\n        .footer {\r\n            display: flex;\r\n            flex-direction: column;\r\n            align-items: center;\r\n            padding: 30px 20px;\r\n            margin-top: 40px;\r\n            border-top: 1px solid #e5e7eb;\r\n            background: #f9fafb;\r\n        }\r\n\r\n        .footer-title {\r\n            font-size: 16px;\r\n            font-weight: 700;\r\n            color: #1f2937;\r\n            margin-bottom: 15px !important;\r\n        }\r\n        \r\n        .footer p {\r\n            font-size: 13px;\r\n            color: #6b7280;\r\n            line-height: 1.8;\r\n            margin: 5px 0;\r\n            text-align: left;\r\n            width: 100%;\r\n            max-width: 500px;\r\n        }\r\n\r\n        @media (max-width: 768px) {\r\n            .footer {\r\n                padding: 25px 15px;\r\n                margin-top: 30px;\r\n            }\r\n\r\n            .footer p {\r\n                font-size: 12px;\r\n            }\r\n        }\r\n		\r\n		/* 이미지 위 클릭 가능한 버튼 영역 */\r\n        .image-button-overlay {\r\n            position: relative;\r\n            width: 100%;\r\n        }\r\n\r\n        .clickable-button {\r\n            position: absolute;\r\n            bottom: 8%;\r\n            left: 50%;\r\n            transform: translateX(-50%);\r\n            width: 80%;\r\n            height: 8%;\r\n            cursor: pointer;\r\n            z-index: 50;\r\n            /* 디버깅용 - 나중에 제거 */\r\n            /* background: rgba(255, 0, 0, 0.3); */\r\n        }\r\n		\r\n        \r\n    </style>\r\n</head>\r\n<body>\r\n    <div class="page-container">\r\n        <!-- 배경 이미지들 (찢어진 후 보일 내용) -->\r\n        <div class="background-images">\r\n            <div class="image-button-overlay">\r\n                <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page03/01_%EC%B2%AD%EB%85%84%20%ED%9A%8C%EC%83%9D%20%EB%9E%9C%EB%94%A9%20%EB%B2%84%ED%8A%BC%ED%8F%AC%ED%95%A8.jpg" alt="청년회생 1">\r\n                <div class="clickable-button" onclick="scrollToForm()"></div>\r\n            </div>\r\n			\r\n            <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page03/02_%EC%B2%AD%EB%85%84%ED%9A%8C%EC%83%9D%20%EB%B3%B5%EC%82%AC.jpg" alt="청년회생 2">\r\n            <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page03/03_%EC%B2%AD%EB%85%84%ED%9A%8C%EC%83%9D%20%EB%9E%9C%EB%94%A9%20%EB%B3%B5%EC%82%AC.jpg" alt="청년회생 3">\r\n            <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page03/04_%EC%B2%AD%EB%85%84%ED%9A%8C%EC%83%9D%20%EB%9E%9C%EB%94%A9%20%EB%B3%B5%EC%82%AC.jpg" alt="청년회생 4">\r\n            <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page03/05_%EC%B2%AD%EB%85%84%ED%9A%8C%EC%83%9D%20%EB%9E%9C%EB%94%A9%20%EB%B3%B5%EC%82%AC.jpg" alt="청년회생 5">\r\n            <img src="https://land.custom-message.co.kr/assets/lawfirm/luda/page03/06_%EC%B2%AD%EB%85%84%ED%9A%8C%EC%83%9D%20%EB%9E%9C%EB%94%A9%20%EB%B3%B5%EC%82%AC.jpg" alt="청년회생 6">\r\n            \r\n            <!-- 폼 페이지 - 이미지 아래에 이어서 -->\r\n            <div class="form-page" id="formPage">\r\n                <div class="form-container">\r\n                    <div class="form-title">\r\n                        <h2>무료 상담 신청</h2>\r\n                        <p>청년회생 전문 상담을 받아보세요</p>\r\n                    </div>\r\n                    <form id="consultForm" action="submit.html" method="POST">\r\n                        <!-- 현재 탕감이 필요한 빚은 얼마인가요 -->\r\n                        <div class="form-group">\r\n                            <label class="form-label">현재 탕감이 필요한 빚은 얼마인가요?</label>\r\n                            <div class="radio-group">\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted2" value="2천만 원 미만" required>\r\n                                    <span class="radio-label">2천만 원 미만</span>\r\n                                </label>\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted2" value="2천만 원 ~ 5천만 원">\r\n                                    <span class="radio-label">2천만 원 ~ 5천만 원</span>\r\n                                </label>\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted2" value="5천만 원 ~ 8천만 원">\r\n                                    <span class="radio-label">5천만 원 ~ 8천만 원</span>\r\n                                </label>\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted2" value="8천만 원 ~ 1억 원 미만">\r\n                                    <span class="radio-label">8천만 원 ~ 1억 원 미만</span>\r\n                                </label>\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted2" value="1억 원 이상">\r\n                                    <span class="radio-label">1억 원 이상</span>\r\n                                </label>\r\n                            </div>\r\n                            <p class="info-text">(신용대출·카드빚·코인·주식 채무가 2천만 원 이상이면 개인회생이 가능한 경우가 대부분입니다)</p>\r\n                        </div>\r\n\r\n                        <!-- 현재 빚이 주로 어떤 종류인가요 -->\r\n                        <div class="form-group">\r\n                            <label class="form-label">현재 빚이 주로 어떤 종류인가요?</label>\r\n                            <div class="radio-group">\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted3" value="신용대출 / 카드빚" required>\r\n                                    <span class="radio-label">신용대출 / 카드빚</span>\r\n                                </label>\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted3" value="코인 · 주식 관련 대출">\r\n                                    <span class="radio-label">코인 · 주식 관련 대출</span>\r\n                                </label>\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted3" value="사업자 대출 (개인 명의)">\r\n                                    <span class="radio-label">사업자 대출 (개인 명의)</span>\r\n                                </label>\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted3" value="병원비 · 생활비 대출">\r\n                                    <span class="radio-label">병원비 · 생활비 대출</span>\r\n                                </label>\r\n                                <label class="radio-option">\r\n                                    <input type="radio" name="inputted3" value="담보대출 (주택 · 아파트)">\r\n                                    <span class="radio-label">담보대출 (주택 · 아파트)</span>\r\n                                </label>\r\n                            </div>\r\n                            <p class="info-text">(2024년 법원 통계 기준 실질 탕감률 평균 70% 이상 사업자 채무는 최대 80%에 가까운 법원 사례)</p>\r\n                        </div>\r\n\r\n                        <!-- 이름 -->\r\n                        <div class="form-group">\r\n                            <label class="form-label">이름</label>\r\n                            <input type="text" name="name" class="input-field" placeholder="이름을 입력해주세요" required>\r\n                        </div>\r\n\r\n                        <!-- 연락처 -->\r\n                        <div class="form-group">\r\n                            <label class="form-label">연락처</label>\r\n                            <div class="tel-group">\r\n                                <input type="text" name="tel1" value="010" class="input-field tel-fixed" readonly>\r\n                                <input type="text" name="tel2" class="input-field" placeholder="1234" maxlength="4" pattern="[0-9]{3,4}" required>\r\n                                <input type="text" name="tel3" class="input-field" placeholder="5678" maxlength="4" pattern="[0-9]{4}" required>\r\n                            </div>\r\n                        </div>\r\n\r\n                        <!-- 상담가능시간 -->\r\n                        <div class="form-group">\r\n                            <label class="form-label">상담 가능 시간</label>\r\n                            <select name="inputted1" class="input-field" required>\r\n                                <option value="">선택해주세요</option>\r\n                                <option value="오전">오전 (09:00 - 12:00)</option>\r\n                                <option value="점심">점심 (12:00 - 14:00)</option>\r\n                                <option value="오후">오후 (14:00 - 18:00)</option>\r\n                            </select>\r\n                        </div>\r\n\r\n                        <!-- 상담메모 -->\r\n                        <div class="form-group">\r\n                            <label class="form-label">상담 메모</label>\r\n                            <textarea name="inputted5" class="input-field" placeholder="상담받고 싶은 내용을 자유롭게 작성해주세요 (선택사항)"></textarea>\r\n                        </div>\r\n\r\n                        <!-- 개인정보 동의 -->\r\n                        <div class="privacy-group">\r\n                            <input type="checkbox" id="privacy" required>\r\n                            <label for="privacy">개인정보 수집 및 이용에 동의합니다. (필수)</label>\r\n                            <button type="button" onclick="openPrivacyModal()" class="privacy-btn">보기</button>\r\n                        </div>\r\n\r\n                        <button type="submit" class="submit-btn">무료 상담 신청하기</button>\r\n                    </form>\r\n                </div>\r\n                \r\n                \r\n             <!-- 푸터 -->\r\n            <div class="footer">\r\n                <p class="footer-title">루다 합동법무사사무소</p>\r\n                <p>사업자등록번호 : 209-44-91325</p>\r\n                <p>대표 : 김현기</p>\r\n                <p>주소 : 서울시 강남구 테헤란로21길 5, 10층(역삼동, 이너스타워)</p>\r\n            </div>\r\n            </div>\r\n        </div>\r\n        \r\n        \r\n\r\n        <!-- 찢어지는 종이 레이어 -->\r\n        <div class="tear-layer">\r\n            <div class="tear-left" id="tearLeft"></div>\r\n            <div class="tear-right" id="tearRight"></div>\r\n        </div>\r\n\r\n        <!-- 가위 애니메이션 -->\r\n        <div class="scissors" id="scissors">✂️</div>\r\n\r\n        <!-- 클릭 영역 -->\r\n        <div class="click-area" id="clickArea"></div>\r\n    </div>\r\n    \r\n    <!-- 개인정보 약관 모달 -->\r\n    <div id="privacyModal" style="display: none; position: fixed; z-index: 9999; left: 0; top: 0; width: 100%; height: 100%; background: rgba(0, 0, 0, 0.6); align-items: center; justify-content: center;">\r\n        <div style="background: white; padding: 30px; border-radius: 16px; max-width: 700px; width: 90%; max-height: 85vh; overflow-y: auto; box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);">\r\n            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; padding-bottom: 15px; border-bottom: 2px solid #eee;">\r\n                <h3 style="font-size: 20px; font-weight: 700; color: #333; margin: 0;">개인정보 처리방침</h3>\r\n                <button onclick="closePrivacyModal()" style="background: none; border: none; font-size: 28px; cursor: pointer; color: #999; width: 36px; height: 36px; display: flex; align-items: center; justify-content: center; border-radius: 50%;">&times;</button>\r\n            </div>\r\n            <div style="font-size: 13px; line-height: 1.7; color: #555;">\r\n                <p style="margin-bottom: 15px;">루다법무사사무소(이하 "본 법무사사무소"라고 함)은 「개인정보 보호법」 제30조에 따라 정보주체의 개인정보를 보호하고 이와 관련한 고충을 신속하고 원활하게 처리할 수 있도록 하기 위하여 다음과 같이 개인정보 처리방침을 수립·공개합니다.</p>\r\n                \r\n                <h4 style="font-size: 15px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제1조(개인정보의 처리목적)</h4>\r\n                <p style="margin-bottom: 10px;">본 법무사사무소가 개인정보 보호법 제32조에 따라 등록․공개하는 개인정보파일의 처리목적은 다음과 같습니다.</p>\r\n                <ul style="margin: 10px 0 10px 20px; padding: 0;">\r\n                    <li>개인정보 파일명 : 인적사항</li>\r\n                    <li>개인정보의 처리목적 : 법률 서비스 제공</li>\r\n                    <li>수집방법 : 생성정보 수집 툴을 통한 수집, 전화/팩스, 서면양식, 홈페이지</li>\r\n                    <li>보유근거 : 통신비밀보호법 등</li>\r\n                    <li>보유기간 : 준영구</li>\r\n                    <li>관련법령 : 표시/광고에 관한 기록 : 6개월, 계약 또는 청약철회 등에 관한 기록 : 5년, 대금결제 및 재화 등의 공급에 관한 기록 : 5년, 소비자의 불만 또는 분쟁처리에 관한 기록 : 3년, 신용정보의 수집/처리 및 이용 등에 관한 기록 : 3년</li>\r\n                </ul>\r\n\r\n                <h4 style="font-size: 15px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제2조(처리하는 개인정보의 항목)</h4>\r\n                <p style="margin-bottom: 5px;">인적사항</p>\r\n                <ul style="margin: 5px 0 10px 20px; padding: 0;">\r\n                    <li>필수항목 : 이름, 휴대전화번호, 접속 로그, 상담신청 절차에서 발생된 정보</li>\r\n                </ul>\r\n\r\n                <h4 style="font-size: 15px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제3조(개인정보의 파기절차 및 파기방법)</h4>\r\n                <p style="margin-bottom: 10px;">본 법무사사무소는 개인정보 보유기간의 경과, 처리목적 달성 등 개인정보가 불필요하게 되었을 때에는 지체없이 해당 개인정보를 파기합니다.</p>\r\n                <ul style="margin: 10px 0 10px 20px; padding: 0;">\r\n                    <li>파기절차: 본 법무사사무소는 파기 사유가 발생한 개인정보를 선정하고, 본 법무사사무소의 개인정보 보호책임자의 승인을 받아 개인정보를 파기합니다.</li>\r\n                    <li>파기방법: 종이에 출력된 개인정보는 분쇄기로 분쇄하거나 소각을 통하여 파기합니다</li>\r\n                </ul>\r\n\r\n                <h4 style="font-size: 15px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제4조(개인정보주체의 권리·의무 및 그 행사방법)</h4>\r\n                <p style="margin-bottom: 5px;">(1) 정보주체는 관계 법령이 정하는 바에 따라 개인정보의 열람, 정정·삭제, 처리정지 및 동의 철회 등 개인정보 보호 관련 권리를 행사할 수 있습니다.</p>\r\n                <p style="margin-bottom: 5px;">(2) 제1항에 따른 권리행사는 본 법무사사무소에 대하여 개인정보 보호법 시행규칙 별지 제8호 서식에 따라 서면, 전자우편, 모사전송(FAX) 등을 통하여 하실 수 있습니다.</p>\r\n                <p style="margin-bottom: 5px;">(3) 제1항의 따른 권리행사는 정보주체의 법정대리인을 통해서도 행사할 수 있으며, 이 경우에는 개인정보 보호법 시행규칙 별지 제11호 서식에 따른 위임장을 본 법무사사무소에 제출해야 합니다.</p>\r\n                <p style="margin-bottom: 10px;">(4) 본 법무사사무소는 정보주체의 권리행사에 관하여 관계 법령이 정하는 바에 따라 지체없이 조치하겠습니다.</p>\r\n\r\n                <h4 style="font-size: 15px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제7조(개인정보 보호책임자)</h4>\r\n                <p style="margin-bottom: 10px;">본 법무사사무소는 개인정보 처리에 관한 업무를 총괄해서 책임지고, 개인정보 처리와 관련한 정보주체의 불만처리 및 피해구제 등을 위하여 아래와 같이 개인정보 보호책임자를 지정하고 있습니다.</p>\r\n                <ul style="margin: 10px 0 10px 20px; padding: 0;">\r\n                    <li>성명 : 김현기</li>\r\n                    <li>직책 : 대표 법무사</li>\r\n                    <li>연락처 : 02-6385-7000</li>\r\n                </ul>\r\n\r\n                <h4 style="font-size: 15px; font-weight: 700; color: #333; margin-top: 20px; margin-bottom: 10px;">제9조(권익침해 구제방법)</h4>\r\n                <p style="margin-bottom: 10px;">정보주체는 아래의 기관에 대해 개인정보 침해에 대한 피해구제, 상담 등을 문의하실 수 있습니다.</p>\r\n                <ul style="margin: 10px 0 10px 20px; padding: 0;">\r\n                    <li>개인정보 침해신고센터 (한국인터넷진흥원) : (국번없이) 118</li>\r\n                    <li>개인정보분쟁조정위원회 : 1833-6972</li>\r\n                    <li>대검찰청 사이버수사과 : (국번없이) 1301</li>\r\n                    <li>경찰청 사이버안전국 : (국번없이) 182</li>\r\n                </ul>\r\n\r\n                <p style="margin-top: 20px; padding: 15px; background: #f9fafb; border-left: 3px solid #1e3a8a; border-radius: 4px; font-size: 12px; color: #666;">※ 이 개인정보처리방침은 2026년 04월 20일부터 적용됩니다.</p>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <script>\r\n        const clickArea = document.getElementById(\'clickArea\');\r\n        const tearLeft = document.getElementById(\'tearLeft\');\r\n        const tearRight = document.getElementById(\'tearRight\');\r\n        const scissors = document.getElementById(\'scissors\');\r\n        const formPage = document.getElementById(\'formPage\');\r\n        const backgroundImages = document.querySelector(\'.background-images\');\r\n\r\n        let isTorn = false;\r\n\r\n        // 클릭/터치로 찢기\r\n        clickArea.addEventListener(\'click\', tearPaper);\r\n        clickArea.addEventListener(\'touchstart\', function(e) {\r\n            e.preventDefault();\r\n            tearPaper();\r\n        });\r\n\r\n        function tearPaper() {\r\n            if (isTorn) return;\r\n            isTorn = true;\r\n\r\n            // 찢어지는 애니메이션\r\n            tearLeft.classList.add(\'torn\');\r\n            tearRight.classList.add(\'torn\');\r\n\r\n            // UI 요소 숨기기\r\n            scissors.classList.add(\'hidden\');\r\n            clickArea.classList.add(\'hidden\');\r\n\r\n            // 0.8초 후 배경 이미지 보이게 + 빚 이미지 완전히 제거\r\n            setTimeout(() => {\r\n                backgroundImages.style.zIndex = \'100\';\r\n                \r\n                // 찢어진 빚 이미지 완전히 제거\r\n                tearLeft.style.display = \'none\';\r\n                tearRight.style.display = \'none\';\r\n            }, 800);\r\n\r\n            // 이미지 끝까지 스크롤하면 폼 표시\r\n            backgroundImages.addEventListener(\'scroll\', checkScrollEnd);\r\n        }\r\n\r\n        function checkScrollEnd() {\r\n            const scrollTop = backgroundImages.scrollTop;\r\n            const scrollHeight = backgroundImages.scrollHeight;\r\n            const clientHeight = backgroundImages.clientHeight;\r\n\r\n            // 끝까지 스크롤했는지 확인 (100px 여유)\r\n            if (scrollTop + clientHeight >= scrollHeight - 100) {\r\n                showForm();\r\n            }\r\n        }\r\n\r\n        function showForm() {\r\n            backgroundImages.removeEventListener(\'scroll\', checkScrollEnd);\r\n            \r\n            // 폼까지 자동 스크롤\r\n            backgroundImages.scrollTo({\r\n                top: backgroundImages.scrollHeight,\r\n                behavior: \'smooth\'\r\n            });\r\n\r\n            // 전화번호 자동 포커스\r\n            const tel2 = document.querySelector(\'input[name="tel2"]\');\r\n            const tel3 = document.querySelector(\'input[name="tel3"]\');\r\n\r\n            tel2.addEventListener(\'input\', function() {\r\n                this.value = this.value.replace(/[^0-9]/g, \'\');\r\n                if (this.value.length === 4) tel3.focus();\r\n            });\r\n\r\n            tel3.addEventListener(\'input\', function() {\r\n                this.value = this.value.replace(/[^0-9]/g, \'\');\r\n            });\r\n        }\r\n\r\n        // 버튼 클릭 시 폼으로 스크롤\r\n        function scrollToForm() {\r\n            const formPage = document.getElementById(\'formPage\');\r\n            formPage.scrollIntoView({ behavior: \'smooth\', block: \'start\' });\r\n        }\r\n\r\n        // 개인정보 약관 모달\r\n        function openPrivacyModal() {\r\n            document.getElementById(\'privacyModal\').style.display = \'flex\';\r\n            document.body.style.overflow = \'hidden\';\r\n        }\r\n\r\n        function closePrivacyModal() {\r\n            document.getElementById(\'privacyModal\').style.display = \'none\';\r\n            document.body.style.overflow = \'auto\';\r\n        }\r\n\r\n        // 모달 배경 클릭 시 닫기\r\n        document.getElementById(\'privacyModal\').addEventListener(\'click\', function(e) {\r\n            if (e.target === this) {\r\n                closePrivacyModal();\r\n            }\r\n        });\r\n\r\n        // 페이지 로드 시 즉시 라디오 검증 적용\r\n        document.addEventListener(\'DOMContentLoaded\', function() {\r\n            const debtRadios = document.querySelectorAll(\'input[name="inputted2"]\');\r\n            const typeRadios = document.querySelectorAll(\'input[name="inputted3"]\');\r\n            \r\n            debtRadios.forEach(radio => {\r\n                radio.addEventListener(\'change\', function() {\r\n                    if (this.value === \'2천만 원 미만\') {\r\n                        alert(\'죄송합니다. 2천만 원 미만 선택 시 신청 할 수 없습니다.\');\r\n                        this.checked = false;\r\n                    }\r\n                });\r\n            });\r\n            \r\n            typeRadios.forEach(radio => {\r\n                radio.addEventListener(\'change\', function() {\r\n                    if (this.value === \'담보대출 (주택 · 아파트)\') {\r\n                        alert(\'죄송합니다. 담보 대출 선택 시 신청 할 수 없습니다.\');\r\n                        this.checked = false;\r\n                    }\r\n                });\r\n            });\r\n        });\r\n\r\n        // 폼 제출 시 검증\r\n        document.getElementById(\'consultForm\').addEventListener(\'submit\', function(e) {\r\n            const formData = new FormData(this);\r\n            const debtValue = formData.get(\'inputted2\');\r\n            const typeValue = formData.get(\'inputted3\');\r\n\r\n            // 2천만원 미만 체크\r\n            if (debtValue === \'2천만 원 미만\') {\r\n                e.preventDefault();\r\n                alert(\'죄송합니다. 2천만 원 미만 선택 시 신청 할 수 없습니다.\');\r\n                document.querySelectorAll(\'input[name="inputted2"]\').forEach(radio => radio.checked = false);\r\n                return false;\r\n            }\r\n            \r\n            // 담보대출 체크\r\n            if (typeValue === \'담보대출 (주택 · 아파트)\') {\r\n                e.preventDefault();\r\n                alert(\'죄송합니다. 담보 대출 선택 시 신청 할 수 없습니다.\');\r\n                document.querySelectorAll(\'input[name="inputted3"]\').forEach(radio => radio.checked = false);\r\n                return false;\r\n            }\r\n\r\n            // 메타 픽셀 추적\r\n            if (typeof fbq !== \'undefined\') {\r\n                fbq(\'track\', \'CompleteRegistration\');\r\n            }\r\n        });\r\n    </script>\r\n</body>\r\n</html>', '2', NULL, '', '', 'Y', '2026-04-23 21:09:41', '2026-04-24 10:30:28', 'cstmsg', 'cstmsg', '이동기', '이동기');
