	(3, 9, 8, 3, 2, 'N', '윤재윤', '8B01E1944D66755EE38FF93F07C559E6', 'DD2693FA215F97B7382A07D797E5E8D7', '010', '37E00D3DF28719BF1BDB30C8FA91D6C3', '6799', '', '', '', '', '', '', '', '', '', '1', '', '', 'divide', 'M', 'ig', 'paid', 'Apple Safari', 'Mozilla/5.0 (iPhone; CPU iPhone OS 26_3_1 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Mobile/23D8133 Instagram 425.0.0.32.59 (iPhone18,3; iOS 26_3_1; ko_KR; ko; scale=3.00; 1206x2622; IABMV/1; 936842409) Safari/604.1', 'N', NULL, 'Y', '2026-04-20 13:46:20', '2026-04-20', '2026-04-20 15:20:22', NULL, NULL, NULL, '121.170.219.110', NULL, '121.170.219.110', NULL, '', '', '', '', '', ''),
	(4, 12, 11, 3, 2, 'N', '박정삼', '097292B77865DFE01623754C55654B02', 'A5C10D6689326886D8BFE33FCD6B681D', '010', '1098DFB06CF23863B946132EDA39A0BF', '6651', '', '', '', '', '', '', '', '', '', '', '내일디비와 중복', '', 'divide', 'M', 'tiktok', 'paid', 'Google Chrome', 'Mozilla/5.0 (Linux; Android 16; SM-S928N Build/BP2A.250605.031.A3) AppleWebKit/537.36 (KHTML, like Gecko) Version/4.0 Chrome/146.0.7680.178 Mobile Safari/537.36 trill_44.5.3', 'N', NULL, 'Y', '2026-04-21 11:45:37', '2026-04-21', '2026-04-23 10:32:41', NULL, NULL, NULL, '2001:4430:c0f3:8797:a165:e9a0:4486:301', NULL, '2001:4430:c0f3:8797:a165:e9a0:4486:301', NULL, '', '', '', '', '', ''),
