  `vs_count` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`vs_date`),
  KEY `index1` (`vs_count`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- 테이블 데이터 cstmsg.cstmsg_visit_sum:~10 rows (대략적) 내보내기
DELETE FROM `cstmsg_visit_sum`;

-- 함수 cstmsg.f_getcode 구조 내보내기
DROP FUNCTION IF EXISTS `f_getcode`;
DELIMITER //
CREATE DEFINER=`cstmsg`@`localhost` FUNCTION `f_getcode`(p_code INT) RETURNS varchar(100) CHARSET utf8mb4 COLLATE utf8mb4_general_ci
BEGIN
    DECLARE return_val VARCHAR(100);

    SELECT CONCAT(comm_pnm, '-', comm_nm)
    INTO return_val
    FROM cstmsg_crm_common
    WHERE comm_idx = p_code
    LIMIT 1;

    RETURN return_val;
END//
DELIMITER ;

-- 함수 cstmsg.f_get_mb_name 구조 내보내기
DROP FUNCTION IF EXISTS `f_get_mb_name`;
DELIMITER //
CREATE DEFINER=`cstmsg`@`localhost` FUNCTION `f_get_mb_name`(p_code INT) RETURNS varchar(100) CHARSET utf8mb4 COLLATE utf8mb4_general_ci
BEGIN
    DECLARE return_val VARCHAR(100);

    SELECT mb_name
    INTO return_val
    FROM cstmsg_member
    WHERE mb_no = p_code
    LIMIT 1;

    RETURN return_val;
END//
DELIMITER ;

